import {IonList,IonItem,IonLabel} from '@ionic/react';
import Link from '../../components/Link';
import MainLink from '../../components/MainLink';
const _traits_tian_xia = {title: "Regional Traits: Tian Xia", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-educated-druggist"><Link to="/trait/educated_druggist">Educated Druggist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osibu, Thuvia, Tian Xia, or Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Any alchemical remedies you administer that provide an alchemical bonus have that bonus increased by 1. These remedies also restore 1 hit point to the target in addition to their usual effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-heir-of-chu-ye"><Link to="/trait/heir_of_chu_ye">Heir of Chu Ye</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Tian Xia</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>If you would take a penalty for using the Heal skill to treat deadly wounds without one or more uses of a healer's kit, that penalty is reduced by 2 (minimum no penalty). Additionally, a creature can benefit from you treating its deadly wounds if you do so within 48 hours of its injury instead of within 24 hours.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-servitor-of-spirits"><Link to="/trait/servitor_of_spirits">Servitor of Spirits</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Tian Xia</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>For as long as you can remember, the spirits have always whispered into your ears and guided you-provided that you appease them. At the start of each day, you can choose one <Link to="/ability/spirits">medium spirit</Link> and accept one of its taboos for 24 hours. As long as you don't break that taboo, once during the next 24 hours, you can add a +1 trait bonus to any one roll, check, or saving throw (but not to AC) listed under your chosen spirit's spirit bonus. Using this ability is a free action that you can use even if it isn't your turn. If you are a medium, the spirit you choose with this trait must be the same as the spirit you are channeling and vice versa</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-honeyed-tongue"><Link to="/trait/honeyed_tongue">Honeyed Tongue</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Amanandar</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>Having matured in the melting pot of New Oppara, you know the customs of the Tian-Shus as well as those of the Taldans, and you utilize this knowledge to create peace between rival groups. You gain a +1 trait bonus on Diplomacy checks, and Diplomacy becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-militia"><Link to="/trait/militia">Militia</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Amanandar</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>As part of Amanandar's militia, you have trained extensively with groups. You gain a +1 trait bonus on attacks made while flanking an opponent.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-dtang-ma-bloodline"><Link to="/trait/dtang_ma_bloodline">Dtang Ma Bloodline</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Dtang Ma</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>As you were born in Dtang Ma and possess one of the favored bloodlines, your sorcerous powers are particularly potent. Select one of the following sorcerer bloodlines: fey, maestro, starsoul, or stormborn. Once per day, you may use one of your bloodline powers as if your sorcerer level were 1 higher than normal. This trait does not give you access to bloodline powers whose level requirements you do not yet meet.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-guerilla"><Link to="/trait/guerilla">Guerilla</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Dtang Ma</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You have spent much time in the rainforests of Dtang Ma, and know its secrets. You gain a +1 trait bonus on Knowledge (nature) checks as well as Survival checks made in the rainforest. One of these skills becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-kami-talker"><Link to="/trait/kami_talker">Kami Talker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Forest of Spirits</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You have traversed the Forest of Spirits numerous times, and have learned how best to communicate with its otherworldly inhabitants. You gain a +2 trait bonus on Diplomacy and Intimidate checks made against outsiders that have the native subtype.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-spiritual-forester"><Link to="/trait/spiritual_forester">Spiritual Forester</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Forest of Spirits</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You grew up in a small settlement along the outskirts of the Forest of Spirits, and have learned much about the woods as well as about their supernatural inhabitants. You gain a +1 trait bonus on Knowledge (nature) and Knowledge (planes) checks, and one of these skills becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-hongal-bloodrider"><Link to="/trait/hongal_bloodrider">Hongal Bloodrider</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Hongal</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You belong to one of the nomadic groups of horseback riders that range throughout Hongal. You gain a +1 trait bonus on Handle Animal and Ride checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-storm-hunter"><Link to="/trait/storm_hunter">Storm Hunter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Hongal</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You learned to hunt in the relentless winds of Hongal, and still make your arrows fly true. When fighting in windy weather, you treat the wind category as one level lower for the purposes of determining penalties on ranged attacks made with normal weapons.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-altruistic-diplomat"><Link to="/trait/altruistic_diplomat">Altruistic Diplomat</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Hwanggot</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>Your upbringing in Hwanggot has influenced you to be both peaceful and wise, and your arguments are consistently sound. You gain a +2 trait bonus on Diplomacy checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-hwan-artist"><Link to="/trait/hwan_artist">Hwan Artist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Hwanggot</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You grew up in Hwanggot, and your artistic talents were cherished and honed from an early age. You have been nurtured on the artistic spirit of Hwanggot. Choose one Perform skill. You gain a +1 trait bonus on checks with that skill, and it becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-conscientious-miner"><Link to="/trait/conscientious_miner">Conscientious Miner</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jinin</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were one of the mithral miners of Jinin, and learned how to extract the delicate ore as well as determine its value. You gain a +1 trait bonus on Appraise checks, and a +1 trait bonus on Profession (miner) checks. In addition, Profession (miner) becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-intrepid-delver"><Link to="/trait/intrepid_delver">Intrepid Delver</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jinin</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>One of the elder elves in Ayajinbo told you many stories of the Darklands beneath the city, and your nerves have hardened to horrors others can hardly fathom. You gain a +2 trait bonus on saving throws against fear effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-border-guard"><Link to="/trait/border_guard">Border Guard</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kwanlai</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You are one of the warriors on the front lines between Kwanlai and Wanshou, and excel at combat against water-dwelling foes. You gain a +2 trait bonus on rolls to confirm critical hits against foes with the aquatic subtype.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-kwanlai-believer"><Link to="/trait/kwanlai_believer">Kwanlai Believer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kwanlai</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were raised in Kwanlai in one of the devout tengu churches, and your dedication to your cause makes your divine abilities particularly potent. You gain a +2 trait bonus on <Link to="/rule/concentration">concentration</Link> checks made while casting divine spells.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-belem-pirate"><Link to="/trait/belem_pirate">Belem Pirate</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Minata</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>The hidden coves and bays of the island of Belem have been your home throughout most of your career as a pirate, and the winding waterways of Minata have trained you well in the art of sailing. You gain a +1 trait bonus on Knowledge (geography) checks and Profession (sailor) checks, and one of these skills becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-wayang-spellhunter"><Link to="/trait/wayang_spellhunter">Wayang Spellhunter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Minata</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You grew up on one of the wayang-populated islands of Minata, and your use of magic while hunting has been a boon to you. Select a spell of 3rd level or below. When you use this spell with a metamagic feat, it uses up a spell slot one level lower than it normally would.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-instigator-of-rebellion"><Link to="/trait/instigator_of_rebellion">Instigator of Rebellion</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Minkai</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>Your rage over the political repositioning within Minkai has led you to incite rage within your compatriots. You have become adept at organizing rallies in opposition to the government. You gain a +1 trait bonus on Diplomacy and Intimidate checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-minkai-advocate"><Link to="/trait/minkai_advocate">Minkai Advocate</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Minkai</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You possess strong ties to Minkai, and spread flattering words regarding your empire. You gain a +1 trait bonus on Bluff checks, and Bluff becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-jungle-resilience"><Link to="/trait/jungle_resilience">Jungle Resilience</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nagajor</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>Having grown up in Nagajor, you are used to the myriad poisons of its people, and have developed a strong immune system. You gain a +2 trait bonus on Fortitude saves against poison effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-snake-bleeder"><Link to="/trait/snake_bleeder">Snake Bleeder</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nagajor</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were a nagaji vassal of knowledgeable nagas, and they taught you much regarding how they concoct their various poisons. You gain a +2 trait bonus on Craft (alchemy) checks when brewing poisons, and Craft (alchemy) becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-mutabi-qi-explorer"><Link to="/trait/mutabi_qi_explorer">Mutabi-qi Explorer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Shanguang</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You belong to one of the nomadic Mutabi-qi tribes that wander the wastes of Shaguang, and you are adept at navigating the seemingly endless desert wastes. You gain a +1 trait bonus on Knowledge (geography) checks and Survival checks made in the desert.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-heavenly-touch"><Link to="/trait/heavenly_touch">Heavenly Touch</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Tianjing</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>Growing up, you were exposed to everyday miracles performed by your half-celestial friends, and some of this magic rubbed off. At will, you can touch a dying creature to stabilize it as a standard action.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-tianjing-temple-guard"><Link to="/trait/tianjing_temple_guard">Tianjing Temple Guard</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Tianjing</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were a stalwart guard of one of Tianjing's magnificent temple cities, and your resolve proved to be of great use during bandit raids. You gain a +1 trait bonus on attacks of opportunity made with polearm weapons.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-jungle-diplomat"><Link to="/trait/jungle_diplomat">Jungle Diplomat</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Valashmai Jungle</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You know the ways and mores of the tribes of the Valashmai Jungle, and how to handle delicate communications with different groups of people. You gain a +1 trait bonus on Diplomacy and Sense Motive checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-valashmai-veteran"><Link to="/trait/valashmai_veteran">Valashmai Veteran</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Valashmai Jungle</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You have traveled to the Valashmai Jungle on numerous occasions, and your prowess in traversing the jungle wilderness makes you a formidable guide and explorer. You gain a +1 trait bonus on Perception checks, and a +1 trait bonus on Survival checks in jungle terrain. One of these skills becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-master-of-peaks"><Link to="/trait/master_of_peaks">Master of Peaks</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Wall of Heaven</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You have made it to the summits of a number of the Wall of Heaven's peaks, and your body is used to the effects of both extreme cold and high altitude. You gain a +2 trait bonus on Fortitude saving throws made against the effects of <Link to="/rule/cold_dangers">cold dangers</Link> and <Link to="/rule/altitude_sickness">altitude sickness</Link>.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-seasoned-climber"><Link to="/trait/seasoned_climber">Seasoned Climber</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Wall of Heaven</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>Your time on the slopes of the Wall of Heaven has improved your ability to surmount great peaks. You gain a +1 trait bonus on Climb checks, and Climb becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-pearl-diver-xidao"><Link to="/trait/pearl_diver_xidao">Pearl Diver (Xidao)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Xidao</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were a pearl harvester for a nation bordering Xidao, and you know just what clues to look for when searching for a worthwhile haul in the briny shallows. You gain a +1 trait bonus on Appraise and Swim checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-trench-navigator"><Link to="/trait/trench_navigator">Trench Navigator</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Xidao</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You've sailed the treacherous waters of the Xidao Gulf in your past, and you can navigate their dangers adroitly. You gain a +1 trait bonus on Knowledge (geography) checks, and a +1 trait bonus on Profession (sailor) checks. One of these skills becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-discerning-beliefs"><Link to="/trait/discerning_beliefs">Discerning Beliefs</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Zi Ha</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You helped the samsarans maintain the magical boundaries around valleys in the Enlightened Peaks, and learned the secrets of avoiding such illusions yourself. You gain a +2 trait bonus on saving throws to disbelieve illusions.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_tian_xia-sound-of-mind"><Link to="/trait/sound_of_mind">Sound of Mind</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Zi Ha</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You have lived in the mountains of Zi Ha and found utter tranquility among the samsarans of the region. You gain a +2 trait bonus on saving throws against mind-affecting effects.</p>
</IonLabel></IonItem></IonList>};
const _traits_north_central_avistan = {title: "Regional Traits: North Central Avistan", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-blood-potion-brewer"><Link to="/trait/blood_potion_brewer">Blood Potion Brewer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Belkzen</p>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>The orcs of Belkzen routinely mix the blood of their enemies with potions they brew to gain some of their foe's strength. Twice per day when you brew a potion, you can add some of an enemy's blood to the mixture. When you do, the potion's caster level is treated as 1 higher when you drink it for the purpose of determining the duration of the potion's effects. This ability has no effect if another creature drinks the potion. This trait does not grant the ability to brew potions.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-dominator"><Link to="/trait/dominator">Dominator</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Belkzen</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link><br/>The blood of dominance runs thick in the savage home of orcs. You receive a +2 trait bonus on all attempts to demoralize an opponent in combat using the Intimidate skill.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-lichblood"><Link to="/trait/lichblood">Lichblood</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Belkzen<br/><strong>Requirements:</strong> Orc, undead bloodrager bloodline</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>You are among the fabled lichblood orcs, and so you command respect among the orcs of Belkzen. You gain a +2 trait bonus on Diplomacy and Intimidate checks made against orcs of Belkzen. You must have the undead bloodrager bloodline to select this trait.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-linebreaker"><Link to="/trait/linebreaker">Linebreaker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Belkzen</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link><br/>Growing up along the border between Belkzen and Lastwall has taught you how to storm enemy battle lines and quickly overwhelm them. When charging, add 10 feet to your base speed.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-near-death-experience"><Link to="/trait/near_death_experience">Near-Death Experience</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Belkzen</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>You had a close brush with death that you survived only thanks to one of the witch doctors of Belkzen, and your body has learned to cling to life in dire situations. You gain a +1 trait bonus on Constitution checks to stabilize, and you don't die until your hit points drop to a negative amount equal to 2 + your Constitution score.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-glory-of-old"><Link to="/trait/glory_of_old">Glory of Old</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Five Kings Mountains</p>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link><br/>In your veins flows the blood of dwarven heroes from Tar Taargadth. You receive a +1 trait bonus on saving throws against spells, spell-like abilities, and poison.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-mountain-guide"><Link to="/trait/mountain_guide">Mountain Guide</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Five Kings Mountains</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You are skilled at getting along in the mountains, enabling you to find hidden trails and secret entrances into the caverns beneath mountains. You gain a +1 trait bonus on Knowledge (geography) and Survival checks when in mountainous areas, and Knowledge (geography) is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-perseverance"><Link to="/trait/perseverance">Perseverance</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Five Kings Mountains</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link><br/>Your time in the Five Kings Mountains has taught you that any obstacle can be endured and overcome. When you have more than one Will saving throw to overcome an effect (such as from greater command or hold person, or by using the good fortune ability of the Luck domain), you receive a +3 trait bonus on the extra Will saves against that effect.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-crusader-tactician"><Link to="/trait/crusader_tactician">Crusader Tactician</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lastwall</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have studied at Vigil's Crusader War College, and are skilled in both heraldry and siege tactics. You gain a +1 trait bonus on Knowledge (engineering) and Knowledge (nobility) checks, and one of these skills is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-draconic-vigil"><Link to="/trait/draconic_vigil">Draconic Vigil</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lastwall</p>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link><br/>As a defender of Lastwall, you have seen the damage the green dragon Zedoran has wrought upon the land. You gain a +1 bonus on initiative rolls when entering combat against creatures of the dragon type or humanoids of the orc subtype.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-lastwall-cavalry-rider"><Link to="/trait/lastwall_cavalry_rider">Lastwall Cavalry Rider</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lastwall</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>From the moment you were old enough to walk, you learned how to ride the mighty warhorses of Lastwall. You gain a +1 trait bonus on Ride checks, and Ride is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-orc-impaler"><Link to="/trait/orc_impaler">Orc Impaler</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lastwall<br/><strong>Requirements:</strong> Knight of Ozem</p>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link><br/>You gain a +2 trait bonus on rolls to confirm critical hits made as part of a charge. This bonus increases to +3 if the critical hit is made against a creature with the orc subtype.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-blooded"><Link to="/trait/blooded">Blooded</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mindspin Mountains</p>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link><br/>Desperate battles have honed your fighting skills against the ancient enemies of the dwarves. You receive a +1 trait bonus on weapon damage rolls against giants, goblins, and orcs.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-coin-hoarder"><Link to="/trait/coin_hoarder">Coin Hoarder</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mindspin Mountains</p>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link><br/>Everything has a price - and it's your job to know it. Your starting cash increases to 500 gp.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-darkblight-survivor"><Link to="/trait/darkblight_survivor">Darkblight Survivor</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nirmathas</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes</Link><br/>Your woodland home in Nirmathas struggles against the tenacious Darkblight, forcing you to steel yourself against its poisonous influence. You gain a +2 trait bonus on Fortitude saving throws against diseases and poisons inflicted by fey, plants, and forest-related hazards.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-fangwood-diplomat"><Link to="/trait/fangwood_diplomat">Fangwood Diplomat</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nirmathas</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You've lived and worked among the disparate guerrilla groups of the Fangwood. You gain a +1 trait bonus on Diplomacy checks, and Diplomacy is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-fangwood-insurgent"><Link to="/trait/fangwood_insurgent">Fangwood Insurgent</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nirmathas</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>You have spent many years living under the canopy of the Southern Fangwood, during which you and your comrades clashed regularly with the soldiers of imperialist Molthune. After years of guerrilla warfare, you've learned to interpret the sounds of the forest to detect signs of enemies. You gain a +1 trait bonus on initiative checks when in a forest. Once per day when in a forest, you can designate yourself or an ally to roll twice for initiative and take either result.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-guerrilla-mender"><Link to="/trait/guerrilla_mender">Guerrilla Mender</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nirmathas</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>With the help of a druidic healer, you narrowly escaped death by disease or poisoning while on the run from Molthuni militias, whether contracting the ailment was an accident or you were the victim of more sinister forces. Whenever you successfully use the Heal skill to treat an ally's poison or disease, you grant the ally an additional +1 trait bonus on the saving throw against the disease or poison. Heal is a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-nirmathi-militia"><Link to="/trait/nirmathi_militia">Nirmathi Militia</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nirmathas</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have served in one of the militia bands of Nirmathas, and have learned valuable skills. Select one of the following skills: Profession (soldier), Ride, or Survival. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-analytical"><Link to="/trait/analytical">Analytical</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>You have been trained in the analytical thought process preferred by the professors of mortal sciences at Lepidstadt University, allowing you to consider a question more carefully when you have time for calm contemplation. When you take 10 on a Knowledge check, add 1 to your result.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-corpse-dodger"><Link to="/trait/corpse_dodger">Corpse Dodger</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link><br/>You spent your formative years in the town of Ravengro, where your proximity to both a prominent graveyard and an infamous prison left you no stranger to the occasional zombie or skeleton. As such, you developed unique methods of dodging these pests. Once per day, you can cast <Link to="/spell/hide_from_undead">hide from undead</Link> as a spell-like ability. The casting time is a swift action and the caster level for this effect is always 1st; this ability is otherwise identical to the spell.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-dreadful-forethought"><Link to="/trait/dreadful_forethought">Dreadful Forethought</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link><br/>As a minor Ustalavic noble, you have friends linked to Karcau's fiendish cults. Your observations give you a keen insight into the blasphemies of the idle rich. You gain a +1 trait bonus on Knowledge (nobility) and Knowledge (planes) checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-educated-druggist"><Link to="/trait/educated_druggist">Educated Druggist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osibu, Thuvia, Tian Xia, or Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Any alchemical remedies you administer that provide an alchemical bonus have that bonus increased by 1. These remedies also restore 1 hit point to the target in addition to their usual effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-ghost-survivor"><Link to="/trait/ghost_survivor">Ghost Survivor</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link><br/>You spent a single night in Harrowstone and managed to survive the terrifying ordeal, though you bore witness to ghosts and numerous other horrors during your short stay. You gain a +2 trait bonus on Knowledge (religion) checks to identify incorporeal undead and a +2 trait bonus on Fortitude saving throws against effects that inflict negative levels.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-lepidstadt-scar"><Link to="/trait/lepidstadt_scar">Lepidstadt Scar</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>You engaged in nonlethal duels at Fifthstones Hill so often that you gained a visible (though minor) scar on your face. Because of this experience, you're unflinching in the heat of combat, calmly analyzing how to lessen the impact of a foe's best attacks. You gain a +1 dodge bonus to AC against attack rolls made to confirm a critical threat against you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-shadow-dealer"><Link to="/trait/shadow_dealer">Shadow Dealer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven</Link><br/>You have survived and thrived in the dark forests of Ustalav by knowing how to make deals with terrible things. You gain a +1 trait bonus on saving throws against fear effects and a +1 trait bonus on Bluff and Diplomacy skills checks against evil fey, monstrous humanoids, and undead.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-skilled-surgeon"><Link to="/trait/skilled_surgeon">Skilled Surgeon</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira or Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Whenever you perform surgery or otherwise must deal damage to remove a condition or affliction, you roll the damage but use the minimum result unless you rolled the maximum result. The amount of hit points or points of ability damage restored each day when you provide long-term care is increased by 1.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-superstitious-ward"><Link to="/trait/superstitious_ward">Superstitious Ward</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You're not frightened of the old wives' tales of vampires and ghosts, and though you try to avoid the undead, you've learned how to deal with them. You may cast <Link to="/spell/disrupt_undead">disrupt undead</Link> once per day as a spell-like ability. This is cast at your highest caster level gained; if you have no caster level, it functions at CL 1st.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-swamp-survivor"><Link to="/trait/swamp_survivor">Swamp Survivor</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link><br/>Leaving Graidmere Swamp is forbidden, and to flee the mire is to court the black dragon Seryzilian's wrath. However, you are one of the few to successfully make it out of the swamp alive. Now, you're resolved to liberate your kinfolk. You gain a +2 bonus on Survival checks to find fresh water, and magical liquids in your possession gain a +2 bonus on Will saves to avoid being corrupted or otherwise spoiled.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-unafraid"><Link to="/trait/unafraid">Unafraid</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link><br/>The horrors of the fog-shrouded land of terror have hardened you. You receive a +2 bonus on all saving throws made against fear affects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_central_avistan-ustalavic-noble"><Link to="/trait/ustalavic_noble">Ustalavic Noble</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You come from an aristocratic family, though your family has long since lost any power or prestige it once had. You gain a +1 trait bonus on Diplomacy and Knowledge (nobility) checks. In addition, your starting money is increased by 100 gp: your "birthright," such as it is.</p>
</IonLabel></IonItem></IonList>};
const _traits_casmaron = {title: "Regional Traits: Casmaron", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-centaur-vengeance"><Link to="/trait/centaur_vengeance">Centaur Vengeance</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Iobaria</p>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link><br/>Your nomadic tribe wanders the Ice Steppes of Iobaria. They live in constant fear of the great white wyrm Sjohvornor and feel helpless to stop the dragon's aggression. Your tribe is filled with wise sages and great warriors, and they resent being cowed by any foe. You vowed that one day you would not have to be afraid of Sjohvornor or any other wyrm. You gain a +2 bonus on saving throws against any dragon's frightful presence.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-iobarian-survivor"><Link to="/trait/iobarian_survivor">Iobarian Survivor</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Iobaria</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Whenever you are exposed to a disease while you are trying to treat an afflicted creature, you gain a +4 trait bonus on your Fortitude saving throw to resist contracting the disease yourself.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-alabaster-odalisque"><Link to="/trait/alabaster_odalisque">Alabaster Odalisque</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jalmeray<br/><strong>Requirements:</strong> Oread</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>The rajahs of Jalmeray favored you for your stately physique and flawless skin, and so endorsed your candidacy for tutelage at the Conservatory on the island of Grand Sarret. Trained to be the perfect bard, courtesan, or undercover operative, you gain a +1 trait bonus on two Charisma-based skills of your choice. In addition, once per day as a swift action, you can brush your fingers against a closed door or stone wall up to 1 foot thick. Doing so allows you to ignore penalties on Perception checks to listen through the designated object for 1 minute.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-candidate-for-perfection"><Link to="/trait/candidate_for_perfection">Candidate for Perfection</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jalmeray</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have begun training to enter one of the <Link to="/rule/houses_of_perfection">Houses of Perfection</Link>, and have honed your body, mind, and spirit into one well-trained weapon. You gain a +1 trait bonus on attack of opportunity attack rolls made with unarmed strikes.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-naga-emissary"><Link to="/trait/naga_emissary">Naga Emissary</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jalmeray<br/><strong>Requirements:</strong> Naga</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast</Link><br/>You were groomed from childhood to act as an emissary to Nagajor's allies in Jalmeray, and you understand much about the Jalmeri people as a result. You gain a +1 trait bonus on Diplomacy checks, and Diplomacy is a class skill for you. In addition, you gain Vudrani as a bonus language.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-secret-of-the-impossible-kingdom"><Link to="/trait/secret_of_the_impossible_kingdom">Secret of the Impossible Kingdom</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Jalmeray</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have studied the ancient lore of Vudra at a monastery in Jalmeray, and have learned a mystical secret that empowers your spellcasting. Pick one spell when you choose this trait - from this point on, whenever you cast that spell, you do so at +1 caster level.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-keleshite-trader"><Link to="/trait/keleshite_trader">Keleshite Trader</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kelesh or Qadira</p>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link><br/>Your cosmopolitan upbringing has given you familiarity with many cultures. You gain two bonus languages and a +2 trait bonus on Knowledge (local) checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-brave-words"><Link to="/trait/brave_words">Brave Words</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ninshaburian</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 25</Link><br/>You inherit your forebears' ability to fight off terror with bragging or insults. As a swift action, when you have the frightened condition, you can function as if you only have the shaken condition for 1 round by shouting at the source of your fear. You must be able to see the source of the fear condition. You can use this trait only once per fear effect. This trait grants no benefits against the shaken or panicked conditions.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-elemental-pupil"><Link to="/trait/elemental_pupil">Elemental Pupil</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link><br/>You have studied at the feet of the masters of Katheer's colleges of magic, and so increased your own mastery of the elements. Choose one of the following energy types: acid, cold, electricity, or fire. When casting a spell of 1st level or higher that deals damage of your chosen energy type, the spell deals 1 extra point of damage of this type.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-emberkin-imposter"><Link to="/trait/emberkin_imposter">Emberkin Imposter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link><br/>You have found it is easier to be mistaken for someone with celestial blood than to reveal your true nature. You gain a +5 trait bonus on Disguise checks when pretending to be an aasimar, and a +2 trait bonus on Diplomacy checks against those you have convinced of your supposed celestial nature.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-empathic-diplomat"><Link to="/trait/empathic_diplomat">Empathic Diplomat</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira or Osirion</p>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link><br/>You have long followed the path of common sense and empathic insight when using diplomacy. You modify your Diplomacy checks using your Wisdom modifier, not your Charisma modifier.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-genie-caller"><Link to="/trait/genie_caller">Genie-Caller</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link><br/>Your exploration of the magic for calling genies has increased your overall aptitude for summoning. Once per day, you may cast one conjuration (summoning) spell as if your caster level were 2 higher than normal.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-keeper-of-the-veil"><Link to="/trait/keeper_of_the_veil">Keeper of the Veil</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link><br/>Even when not cloaked in magic, your training has taught you how to conceal your true nature. You gain a +1 competence bonus on Bluff and Disguise checks, and one of these skills (your choice) is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-merchant-of-katheer"><Link to="/trait/merchant_of_katheer">Merchant of Katheer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link><br/>You grew up among the market stalls of the greatest trading post in all the world, and can almost smell the value of an item before you touch it. You gain a +1 trait bonus to Appraise checks, and Appraise is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-paraheen-weaponsmith"><Link to="/trait/paraheen_weaponsmith">Paraheen Weaponsmith</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link><br/>You are a descendant of a long line of skilled dwarven weapon makers or have apprenticed under such artisans. Either way, you learned their long-held secrets relating to the production of magical arms and armor. You treat your caster level as 1 higher for purposes of creating magical weapons, and gain a +1 trait bonus on Craft checks to create magical armor, shields, or weapons.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-rider-of-paresh"><Link to="/trait/rider_of_paresh">Rider of Paresh</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira<br/><strong>Requirements:</strong> <Link to="/feat/mounted_combat">Mounted Combat</Link> feat</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link><br/>You call the Plains of Paresh home, whether you were born among the plains' tribes or in the glittering towers of Katheer. The horses are your kin. When mounted and making a charge, your mount's speed is increased by 10 feet.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-shaer"><Link to="/trait/shaer">Shaer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira<br/><strong>Requirements:</strong> Kelish</p>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link><br/>Qadira is a land of poetry, and you have grown up immersed in the words and language of that culture. Your facility with the language is evident to all when you speak. You gain a +2 trait bonus on Bluff and Diplomacy checks when speaking with anyone fluent in Kelish.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-skilled-surgeon"><Link to="/trait/skilled_surgeon">Skilled Surgeon</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira or Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Whenever you perform surgery or otherwise must deal damage to remove a condition or affliction, you roll the damage but use the minimum result unless you rolled the maximum result. The amount of hit points or points of ability damage restored each day when you provide long-term care is increased by 1.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-venicaan-medic"><Link to="/trait/venicaan_medic">Venicaan Medic</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link><br/>You have studied at the College of Medicaments and Chirurgery, and know by sight the signs of ailments and toxins you might encounter. You gain a +2 trait bonus to Heal checks to treat diseases or poisons, and Heal is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-walking-ward"><Link to="/trait/walking_ward">Walking Ward</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira</p>
<p><strong>Sources</strong> <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link><br/>Your training included constant exposure to elemental forces. Choose one of the following energy types: acid, cold, electricity, or fire; you gain a +1 bonus on saving throws against spells that deal damage of this type or have this subtype.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_casmaron-watching-taldor"><Link to="/trait/watching_taldor">Watching Taldor</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira<br/><strong>Requirements:</strong> Characters from Qadira who have had family members, neighbors, or friends affected by Taldan aggression or who have fallen victim to this hatred themselves.</p>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link>, <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link><br/>You have spent your adult life waiting for Taldor to give you an excuse to fight. You gain a +1 trait bonus on initiative checks, and if you are able to act during the surprise round of an encounter, you can draw a weapon (but not a potion or magic item) as a free action during that round.</p>
</IonLabel></IonItem></IonList>};
const _traits_north_west_avistan = {title: "Regional Traits: Northwestern Avistan", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-azlanti-scholar-hftf"><Link to="/trait/azlanti_scholar_hftf">Azlanti Scholar (HFtF)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ironbound Archipelago<br/><strong>Requirements:</strong> Cannot be an elf</p>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link><br/>Your interactions with the elves of the Mordant Spire have taught you much about Azlanti artifacts, and you now share the Mordant Spire elves' fascination with these relics. You gain Azlanti as a bonus language, and you gain a +2 trait bonus on Appraise and Use Magic Device checks when attempting to identify or use authentic Azlanti artifacts.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-chillblight-emissary"><Link to="/trait/chillblight_emissary">Chillblight Emissary</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link><br/>You have spent considerable time at Chillblight, but have escaped this unearthly fey outpost. You gain DR 1/cold iron but become sickened for 1 round if damaged by a cold iron weapon.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-debt-to-a-witch"><Link to="/trait/debt_to_a_witch">Debt to a Witch</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Your life was spared in youth by the magic of a White Witch healer who was using your survival to perpetuate her agenda. Her magic was painful, but it made your body stronger. You gain a +2 trait bonus on saving throws against spells with the cold descriptor and against the dangers of cold weather.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-fey-hex"><Link to="/trait/fey_hex">Fey Hex</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link><br/>You have learned to incorporate fey enchantments into your hexes to snare victims that shake off your curses. Once per day as a free action, when a creature succeeds at its saving throw against your hex that cannot target the same creature more than once per day, you can declare that creature to be subject to your fey hex. You can attempt the failed hex against the creature a second time, so long as you do so within 1 minute.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-jadwiga-medicine"><Link to="/trait/jadwiga_medicine">Jadwiga Medicine</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Once per day as an immediate action when you cast a spell of the healing subschool or a hex that produces the effect of such a spell, you can attempt an Intimidate check to demoralize your target or anyone who can see you within 30 feet. You gain a +2 trait bonus on this check.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-whitethrone-gourmand"><Link to="/trait/whitethrone_gourmand">Whitethrone Gourmand</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link><br/>You grew up privileged in the city of Whitethrone, and indulged in many exotic and unnerving pleasures. You gain a +1 trait bonus on saves against any effect causing the nauseated or sickened condition and against all ingested poisons.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-winter-warrior"><Link to="/trait/winter_warrior">Winter Warrior</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You grew up in the icy lands of Irrisen, and surviving in the cold snows of winter is second nature to you. You gain a +1 trait bonus on Stealth and Survival checks in ice- or snow-covered terrain.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-winters-soul"><Link to="/trait/winters_soul">Winter's Soul</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>The eternal winter of Irrisen is as much a part of you as it is the land. You may cast <Link to="/spell/ray_of_frost">ray of frost</Link> once per day as a spell-like ability. This is cast at your highest caster level gained; if you have no caster level, it functions at CL 1st.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-witch-tongued"><Link to="/trait/witch_tongued">Witch-Tongued</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Irrisen</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven</Link><br/>Hailing from frozen Irrisen, where witches rule the land, you deal with others in a cool, calculated way. You gain a +1 trait bonus on Diplomacy checks, and you gain a +1 trait bonus on Intimidate checks against non-witches.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-blessed-of-the-norns"><Link to="/trait/blessed_of_the_norns">Blessed of the Norns</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven</Link><br/>You or one of your parents belonged to a coven that honored the norns-powerful fey seers - and you still bear their favor in the form of a subtle sense for danger. You gain a +2 trait bonus on Perception checks to notice traps and ambushes, and a +1 trait bonus to your AC against traps and during any surprise round in which you are caught unaware.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-call-of-the-longships"><Link to="/trait/call_of_the_longships">Call of the Longships</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link><br/>Your blood sings with longing to relive the adventures of one of your ancestors, and you are inexorably drawn to the sea. You gain a +1 trait bonus on Profession (sailor) checks and a +1 trait bonus on attack rolls made onboard ships.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-friend-of-the-fey"><Link to="/trait/friend_of_the_fey">Friend of the Fey</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have a special relationship with the fey, having grown up in close proximity to them. You gain a +2 trait bonus on Diplomacy checks against fey creatures.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-frostborn"><Link to="/trait/frostborn">Frostborn</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link><br/>Long nights in the frigid winters of the north have inured you to cold. You gain a +4 trait bonus on any savings throws made to resist the effects of cold environments, as well as a +1 trait bonus on all saving throws against cold effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-huldras-luck"><Link to="/trait/huldras_luck">Huldra's Luck</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link><br/>At some point in your life, you were touched by a fey creature called a huldra and inherited a bit of its luck. Once per day, you may choose to gain a +1 luck bonus on a single saving throw, attack roll, or skill check.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-viking-blood"><Link to="/trait/viking_blood">Viking Blood</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have the imposing build of a Viking, and people of the south fear your unpredictable nature. You gain a +1 trait bonus on Intimidate checks, and Intimidate is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-warrior-poet"><Link to="/trait/warrior_poet">Warrior Poet</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lands of the Linnorm Kings</p>
<p><strong>Sources</strong> <Link to="/source/dwarves_of_golarion">Dwarves of Golarion</Link><br/>You were trained by the skalds, keepers of the oral tradition of Kalsgard. You gain a +1 trait bonus on Knowledge checks related to dwarves (dwarven history, dwarven construction, and so on) and a +1 trait bonus on Fortitude saves in any round in which you use a bardic performance ability.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-open-minded-explorer"><Link to="/trait/open_minded_explorer">Open-Minded Explorer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Averaka</p>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion</Link><br/>You grew up constantly interacting with people who speak unfamiliar languages and have diverse customs; your manners may not be polished, but your acceptance of others is genuine. You gain a +1 trait bonus on Diplomacy checks. This bonus increases to +2 when you're speaking the racial or ethnic language of the target creature.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-whole-hearted"><Link to="/trait/whole_hearted">Whole-Hearted</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Averaka</p>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion</Link><br/>Though most outsiders expect your mind to be conflicted, full of self-doubt, and mired in resentment and suspicion, you're truly comfortable in your skin. You gain a +2 trait bonus on saving throws against charms and compulsions.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-fey-mediator"><Link to="/trait/fey_mediator">Fey Mediator</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Grungir Forest</p>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link><br/>You gain Sylvan as a bonus language. Additionally, choose Bluff, Diplomacy, or Knowledge (nature). That skill is a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-big-game-hunter"><Link to="/trait/big_game_hunter">Big Game Hunter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link><br/>You have spent long hours hunting giant creatures and have become skilled at bringing them down quickly. You gain a +1 trait bonus on weapon damage rolls against Large or larger creatures of the animal type.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-free-people"><Link to="/trait/free_people">Free People</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords<br/><strong>Requirements:</strong> Kellid</p>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link><br/>The independent tribes from the Realm of the Mammoth Lords hold little regard for the control others wield over free people. Their willful, independent streak makes them suspicious of any attempt to guide their behavior. You gain a +1 trait bonus on Sense Motive checks and on Will saves against mind-affecting effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-mammoth-master"><Link to="/trait/mammoth_master">Mammoth Master</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link><br/>You have experience trapping and training large creatures such as mammoths, mastodons, woolly rhinoceroses, and other megafauna. You gain a +4 trait bonus on Handle Animal checks related to these creatures.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-screaming-leap"><Link to="/trait/screaming_leap">Screaming Leap</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>The rocky foothills of your homeland are ideal for staging leaping ambushes that leave your victims battered and routed. You gain a +1 trait bonus on melee damage rolls when you make a charge attack from higher ground. Once per day, when you make a charge attack from higher ground, you can use the Intimidate skill to demoralize your target as a swift action.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-spirit-animal"><Link to="/trait/spirit_animal">Spirit Animal</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_north">People of the North</Link><br/>A spirit animal watches over you. Choose one of the following spirit animals. The benefit you receive depends on which of the following spirit animals you choose.</p>
<p><strong>Mammoth:</strong> You gain a +1 trait bonus on Fortitude saves.<br/><strong>Smilodon:</strong> You gain a +1 trait bonus on Reflex saves.<br/><strong>Woolly Rhinoceros:</strong> You gain a +1 trait bonus on Will saves.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-superstitious-isp"><Link to="/trait/superstitious_isp">Superstitious (ISP)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Realm of the Mammoth Lords</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You are distrustful of any magic that goes beyond your native shamanic ways. As long as you do not possess any levels in a class that grants arcane spellcasting power, you gain a +1 trait bonus on all saving throws against arcane spells.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-hermean-paragon"><Link to="/trait/hermean_paragon">Hermean Paragon</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Steaming Sea</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You are a product of Hermea's breeding programs - either your parents were chosen to be citizens, or you were, but later failed to live up to the island's high standards. Whatever the case, you are quicker than normal members of your race, and gain a +2 trait bonus on Initiative checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-mordant-heritage"><Link to="/trait/mordant_heritage">Mordant Heritage</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Steaming Sea</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/elves_of_golarion">Elves of Golarion</Link><br/>You have lived among the Mordant Spire elves and know their strange ways. You gain a +1 trait bonus on Swim checks and a +1 trait bonus on saving throws against enchantment effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-caravan-nomad"><Link to="/trait/caravan_nomad">Caravan Nomad</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia<br/><strong>Requirements:</strong> Kitsune</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast</Link><br/>Your family has lived on the open roads of Varisia for untold generations, impersonating nomadic Varisians. You gain a +1 trait bonus on Bluff and Perform checks, and one of these skills is a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-cheap-to-feed"><Link to="/trait/cheap_to_feed">Cheap to Feed</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion or Varisia<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>Life in a big city taught the consequences of pride. Now you have no qualms about pointing out how little of a burden your upkeep would prove to potential employers, captors, innkeepers, or anyone else able to provide you with the necessities of life. You gain a +3 trait bonus on Bluff checks made in order to gain food, water, or shelter.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-cliff-master"><Link to="/trait/cliff_master">Cliff-Master</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia<br/><strong>Requirements:</strong> Goblin</p>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion</Link><br/>You are adept at scavenging along the cliffs by the sea, and have become a skilled climber. You gain a +1 trait bonus on all Climb and Survival checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-greenskin-stalker"><Link to="/trait/greenskin_stalker">Greenskin Stalker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger, River Kingdoms, or Varisia</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>You're a member of the Greenskin Stalkers. Due to your affiliation with this brotherhood of goblin slayers, you've learned to think and act like a goblin, as disturbing as that sounds. You receive a +1 trait bonus on Bluff, Knowledge, Perception, Sense Motive, and Survival checks against or concerning goblinoids. You can also attempt Knowledge checks concerning goblinoids untrained.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-holy-tattoo"><Link to="/trait/holy_tattoo">Holy Tattoo</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link><br/>When you had your deity's holy symbol tattooed on your body by a Sczarni tattooist years ago, you never imagined it would save your life. Your holy symbol tattoo functions in all ways as a holy symbol. When you use your holy symbol tattoo to keep a vampire at bay, the DC for the vampire to overcome its revulsion is 28 (rather than the normal 25).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-humble-beginnings"><Link to="/trait/humble_beginnings">Humble Beginnings</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>You didn't have any intention of becoming an adventurer, but a single, unexpected confrontation changed everything. Choose one of the following: boot, bucket, frying pan, mug, rolling pin, spade, or stool. You are treated as having the Catch Off-Guard feat when wielding the chosen item. (These items should all be considered improvised melee weapons that deal 1d4 points of bludgeoning damage.)</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-left-behind"><Link to="/trait/left_behind">Left Behind</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse or Varisia<br/><strong>Requirements:</strong> Elf</p>
<p><strong>Sources</strong> <Link to="/source/elves_of_golarion">Elves of Golarion</Link><br/>Having been born to those who chose to remain on Golarion during the Age of Darkness in the Mwangi Expanse, you understand the people of this world better than most elves. You gain a +1 trait bonus on Diplomacy checks when interacting with Forlorn elves and non-elf races.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-local-know-it-all"><Link to="/trait/local_know_it_all">Local Know-It-All</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>Choose a community that you've lived in for at least 5 years. You gain a +2 trait bonus on Knowledge (local) checks related to that community.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-regional-influence"><Link to="/trait/regional_influence">Regional Influence</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>Although you live some distance from the city-state your community owes fealty to, you've been influenced by its sophisticated urban ways. Determine the city-state of which your home is a holding. You gain a +1 trait bonus on checks with one Profession skill and one of the following benefits.</p>
<p><strong>Korvosa:</strong> Gain Infernal as a bonus language. If you already have this language, gain a +1 trait bonus on Diplomacy checks.<br/><strong>Magnimar:</strong> Gain one random <Link to="/eq-misc/varisian_idol">Varisian idol</Link>.<br/><strong>Riddleport:</strong> Gain a +1 trait bonus on Swim checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-regional-recluse"><Link to="/trait/regional_recluse">Regional Recluse</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>Your home community prides itself on remaining independent from Varisia's city-states. Choose one of Varisia's unaffiliated settlements from this list below. You gain a +1 trait bonus on Survival checks and one of the following benefits.</p>
<p><strong>Arsmeril or Crying Leaf:</strong> Gain a +1 trait bonus on Perception checks made at night.<br/><strong>Ilsurian:</strong> Gain proficiency with light shields.<br/><strong>Sanos Forest or Whistledown:</strong> Gain Gnome as a bonus language. If you already have this language, gain a +1 trait bonus on Stealth checks made in forested areas.<br/><strong>Turtleback Ferry:</strong> Gain a +1 bonus to damage on all attacks against creatures of the giant type.<br/><strong>Urglin:</strong> Gain Orc as a bonus language. If you already know this language, gain a +1 trait bonus on Intimidate checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-shoanti-tribesman"><Link to="/trait/shoanti_tribesman">Shoanti Tribesman</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You were born or adopted into a Shoanti tribe. Choose one of the following skills: Climb, Survival, or Swim. You gain a +1 trait bonus on this skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-town-gossip"><Link to="/trait/town_gossip">Town Gossip</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>Choose a community that you've lived in for at least 5 years. You gain a +2 trait bonus on Diplomacy checks while in that community.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-varisian-wanderer"><Link to="/trait/varisian_wanderer">Varisian Wanderer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Varisia</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You were raised among or have spent time with a group of Varisian nomads, whether travelers, Sczarni criminals, or entertainers, and have learned their ways. Choose one of the following skills: Perform (choose one type), Profession (fortune-teller), or Sleight of Hand. You gain a +1 trait bonus on this skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-coincunning"><Link to="/trait/coincunning">Coincunning</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Janderhoff</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>Whether from working with dwarven merchants or being one yourself, you've developed a distinctly dwarven business sense. You receive a +2 trait bonus on Perception checks to notice coins, gems, jewelry, and valuable trade goods. You gain a chance to notice such goods whenever you pass within 10 feet of them, whether or not you are actively looking.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-emissary"><Link to="/trait/emissary">Emissary</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kaer Maga</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>Accustomed to the strange residents of Kaer Maga, you have few prejudices. You gain a +2 trait bonus on Diplomacy checks when dealing with aberrations, monstrous humanoids, undead, and creatures with the giant subtype.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-roof-racer"><Link to="/trait/roof_racer">Roof Racer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Korvosa</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>You've spent more than your fair share of time among the strange sloping slums that cover the rooftops of much of Old Korvosa. When using the Acrobatics skill to make a long jump, you treat the DC of the skill check as if the distance being jumped were 5 feet shorter than it actually is.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-savage-breaker"><Link to="/trait/savage_breaker">Savage Breaker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Korvosa</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>You openly despise the crude Shoanti and their backward ways. You gain a +2 trait bonus on combat maneuver checks made to sunder clubs, earth breakers, klars, hide armor, primitive armor and weapons, and any other equipment the GM deems "barbarian-made."</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-empyreal-cultist"><Link to="/trait/empyreal_cultist">Empyreal Cultist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Magnimar</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>Your faith in the empyreal lords - a host of good demigods - and your fascination with the legendary Angel of the Arvensoar have you constantly on the hopeful lookout for celestial messengers. Choose an empyreal lord as your patron deity. You gain Celestial as a bonus language and a +1 trait bonus on Diplomacy checks when dealing with good-aligned humanoids.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-underbridge-dweller"><Link to="/trait/underbridge_dweller">Underbridge Dweller</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Magnimar</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>You were raised in the Shadow district of Magnimar beneath the Irespan, a veiled place the light of the sun touches for only 3 hours per day. Your well-founded suspicions grant you a +2 trait bonus on Perception checks in dim light, and Perception is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-cypher-resistance"><Link to="/trait/cypher_resistance">Cypher Resistance</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>You have grown up near the Cyphergate, passing under its arch countless times in your lifetime. You can recount the runes from memory, and repeated exposure has imbued you with a faint resistance to runic magic. You gain a +2 trait bonus on saving throws against spells with the word <Link to="/main/spell_groupings">"glyph" or "symbol"</Link> in their name.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-cyphermage-backer"><Link to="/trait/cyphermage_backer">Cyphermage Backer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You've sold relics to a <Link to="/rule/cyphermage">Cyphermage</Link> in the past, and she's agreed to assist you with future findings. When in Riddleport, you can use your contact to gain information about artifacts and history. Treat this ability as a single Knowledge (arcana) or Knowledge (history) check with a skill bonus of +15. You may make this check once per day that you spend in Riddleport. You can make a new check every day. Each time you do so, you can choose whether to use Knowledge (arcana) or Knowledge (history).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-eager-combatant"><Link to="/trait/eager_combatant">Eager Combatant</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You're so excited to board other ships that you're frequently the first one over the rail, regardless of the danger. You gain a +1 trait bonus on attack rolls made while onboard an enemy ship.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-gold-goblin-regular"><Link to="/trait/gold_goblin_regular">Gold Goblin Regular</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You're a frequent customer at the Gold Goblin Gambling Hall and enjoy some popularity within its walls. You gain a +1 trait bonus on Profession (gambling) checks and a +2 trait bonus on Diplomacy checks made to gather information when in Riddleport.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-shipboard-caster"><Link to="/trait/shipboard_caster">Shipboard Caster</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You feel an affinity with ships and the sea, and the rolling rhythm of the waves helps focus your mind. When on a ship or other water-going vessel, you gain a +3 bonus on <Link to="/rule/concentration">concentration</Link> checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_west_avistan-winners-luck"><Link to="/trait/winners_luck">Winner's Luck</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Riddleport</p>
<p><strong>Sources</strong> <Link to="/source/varisia_birthplace_of_legends">Varisia, Birthplace of Legends</Link><br/>Winning at the tables in Riddleport's gambling houses can be as devastating as losing. Years of dodging the jealous blows of card table patrons have given you a sixth sense for when your luck is about to run out. Whenever you succeed at a Reflex saving throw, you may draw a weapon as an immediate action, or a hidden weapon as a move action.</p>
</IonLabel></IonItem></IonList>};
const _traits_north_east_avistan = {title: "Regional Traits: Northeastern Avistan", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-issian-noble"><Link to="/trait/issian_noble">Issian Noble</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Brevoy</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You are a scion of one of the warring noble houses of Brevoy, and are well versed in maneuvering though the cutthroat world of Brevic politics. You gain a +1 trait bonus on Knowledge (nobility) and Sense Motive checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-swordlords-page"><Link to="/trait/swordlords_page">Swordlord's Page</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Brevoy</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have trained under the Aldori swordlords, and though not yet a swordlord yourself, you have learned how to strike hard with your weapon. You gain a +1 attack bonus to confirm critical hits when using an edged weapon you are proficient with.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-child-of-the-crusades-isp"><Link to="/trait/child_of_the_crusades_isp">Child of the Crusades (ISP)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mendev</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>Your parents stood strong against the demons of the Worldwound, facing down the worst of this world and the Great Beyond. You have inherited their indomitable spirit, and you gain a +2 trait bonus on all saves against fear.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-cynic"><Link to="/trait/cynic">Cynic</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mendev</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>As a Mendevian native, you have seen all manner of people claiming holy motives, and you have learned to judge them by their deeds, rather than their words. You gain a +1 trait bonus on Sense Motive checks, and Sense Motive is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-demon-eradicator"><Link to="/trait/demon_eradicator">Demon Eradicator</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mendev</p>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link><br/>Anytime an outsider with the demon subtype must make a Will save against one of your spells, increase the DC of that save by +1.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-gallant-imposter"><Link to="/trait/gallant_imposter">Gallant Imposter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mendev</p>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link><br/>You gain a +1 trait bonus on Knowledge (nobility) and Knowledge (religion) checks. In addition, you gain a +2 trait bonus on both Disguise and Bluff checks while attempting to impersonate a knight.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-ancestral-weapon"><Link to="/trait/ancestral_weapon">Ancestral Weapon</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>You have inherited a sacred tribal weapon wielded by your forebears since the days before the Rain of Stars, and you were trained in its use from a young age. Select either <Link to="/eq-material/cold_iron">cold iron</Link> or <Link to="/eq-material/alchemical_silver">silver</Link>. You begin play with a masterwork melee weapon made of the material of your choice. You must be proficient with this weapon, and its combined cost cannot exceed 500 gp. You gain a +1 trait bonus on attack rolls with weapons made of the selected material.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-blighted-physiology"><Link to="/trait/blighted_physiology">Blighted Physiology</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>Exposure to the corruption that seeps through every drop of water and grain of dirt in Numeria has altered your body. Horrific growths beneath your skin provide you a +1 natural armor bonus to AC, but your body does not work as a normal creature's would. You become sickened for 1 round anytime you receive magical healing.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-resourceful-scavenger"><Link to="/trait/resourceful_scavenger">Resourceful Scavenger</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link><br/>Living in Numeria required you to become an expert scavenger, searching through ruins and crash sites for valuables and sustenance. Years spent in this pursuit have given you a keen eye for finding valuables and potentially useful resources in the unlikeliest places. You gain a +2 trait bonus on Perception checks when you search a location for valuables or resources. Appraise is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-skymetal-affinity"><Link to="/trait/skymetal_affinity">Skymetal Affinity</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link><br/>You gain a +2 trait bonus on Fortitude saves against the negative effects of <Link to="/eq-material/skymetal">skymetals</Link>, as well as a +2 trait bonus on Craft checks made to create weapons or armor out of skymetals.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-technic-tinkerer"><Link to="/trait/technic_tinkerer">Technic Tinkerer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You managed to uncover some lesser secrets of the Technic League, and have mastered a minor bit of magic. Choose a 0-level spell. You may cast that spell once per day as a spell-like ability. This is cast at your highest caster level gained; if you have no caster level, it functions at CL 1st.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-technological-brewmaster"><Link to="/trait/technological_brewmaster">Technological Brewmaster</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>You have learned the secret of creating potions using advanced scientific techniques so strange that some might consider them alien. When brewing a potion, you can increase its base creation cost by 10% to brew it in half the normal amount of time. This trait does not grant the ability to brew potions.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-touched-by-the-sky"><Link to="/trait/touched_by_the_sky">Touched by the Sky</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Numeria</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>Somehow, you managed to retrieve a rare vial of fluid from a piece of crashed wreckage on the plains of Numeria. Before you could be caught with the contraband, you drank it. You now have the ability to stabilize a dying creature with a touch as a standard action.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-alien-origins"><Link to="/trait/alien_origins">Alien Origins</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Silver Mount</p>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link><br/>You are in some way tied to the mysterious alien monument known as Silver Mount in Numeria, but you have forgotten an important piece of your past. Perhaps you were a metallurgist's experiment gone awry, a rediscovered automaton that escaped the mountain's confines, or the result of some equally enigmatic phenomenon. Regardless, your unusual origins mark you as somehow different from others, and you know the gaps in your memory hold the key to your past. You start play with a unique compass that doesn't point north and is riddled with indecipherable alien markings - the only object you have that you know to be tied to your home. In addition, your inscrutable mannerisms give you a +2 trait bonus on opposed Bluff checks.</p>
<p><strong>Suggestion:</strong> Consider being a member of the <Link to="/race/android">android race</Link>.*</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-abyssal-eavesdropper"><Link to="/trait/abyssal_eavesdropper">Abyssal Eavesdropper</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sarkoris or The Worldwound</p>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link><br/>Having grown up near the Worldwound, you have a rough understanding of the demons' guttural babble. You add Abyssal to your list of languages known, though you take a -2 penalty on Diplomacy, Intimidate, and Bluff checks made while speaking Abyssal, as well as a -2 penalty on Linguistics checks made to read Abyssal text. If you gain Abyssal as a language again at a later time (such as by taking a rank in Linguistics and selecting Abyssal as a learned language), these skill check penalties become +2 trait bonuses instead.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-demon-proof-mind"><Link to="/trait/demon_proof_mind">Demon-Proof Mind</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sarkoris or The Worldwound</p>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link><br/>You are used to the maddening energy fluctuations emanating from the Worldwound, and have steeled your mind against their influence. You gain a +2 trait bonus on saving throws against the mind-affecting effects of evil outsiders.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-demonbane-summoner"><Link to="/trait/demonbane_summoner">Demonbane Summoner</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Worldwound</p>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook</Link><br/>Your line is derived directly from the god callers of Sarkoris. You adamantly oppose the demonic forces of the Worldwound in hopes of reclaiming your lost lands. The attacks of creatures you summon are treated as cold iron for the purpose of overcoming damage reduction.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_north_east_avistan-wardbreaker"><Link to="/trait/wardbreaker">Wardbreaker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Worldwound</p>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link><br/>You have studied techniques designed to pierce magical protections, with the goal of assisting your Abyssal masters in bringing down the wardstones that guard the borders of Mendev. Once per day, you can attempt a melee touch attack against an opponent that you believe has a deflection bonus to AC. If your attack is successful, your foe's deflection bonus to AC is halved (to a minimum of +0) for a number of rounds equal to your Charisma modifier. You can use this ability twice per day at 10th level and three times per day at 20th level.</p>
</IonLabel></IonItem></IonList>};
const _traits_south_east_avistan = {title: "Regional Traits: Southeastern Avistan", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-absalom-hotspur"><Link to="/trait/absalom_hotspur">Absalom Hotspur</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Absalom</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You grew up on the streets of Absalom and have worked as both guide and bodyguard for visitors to the city. You gain a +1 trait bonus on Initiative checks and Knowledge (local) checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-destined-for-greatness"><Link to="/trait/destined_for_greatness">Destined for Greatness</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Absalom</p>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link><br/>Ever since you were a child growing up in one of Absalom's vast city quarters, you've been obsessed with the Starstone Cathedral and the prospect of acquiring true divinity by passing the Test of the Starstone. Though it remains to be seen whether you will ever achieve your long-standing dream, your fascination with the would-be deities who enter the Starstone Cathedral and never come back has granted you no small measure of savvy when it comes to preparing to explore dungeons. You start with a kit worth no more than 300 gp, and the expendable contents of the kit are automatically restored to their original capacity at no cost to you whenever you enter a settlement with a population of at least 2,500.</p>
<p><strong>Suggestion:</strong> Consider playing a character who worships, reveres, or perhaps even envies one of the Ascended: Cayden Cailean, Iomedae, or Norgorber.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-sophisticated-citizen"><Link to="/trait/sophisticated_citizen">Sophisticated Citizen</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Absalom</p>
<p><strong>Sources</strong> <Link to="/source/merchants_manifest">Merchant's Manifest</Link><br/>You grew up in Absalom, and as a child you learned trivia about people and places from all across the world. Choose Knowledge (geography), Knowledge (local), or Sense Motive; that skill is a class skill for you. In addition, you know one additional bonus language.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-andoren-freedom-fighter"><Link to="/trait/andoren_freedom_fighter">Andoren Freedom Fighter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You've dedicated your life to fighting against oppression, tyranny, and slavery. You gain a +1 trait bonus on attack and damage rolls against slavers or any creature holding someone against their will.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-chainbreaker"><Link to="/trait/chainbreaker">Chainbreaker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You're an expert at rescuing slaves. You know that a few slaves freed from their chains can help turn the tide during a boarding action. You gain a +1 trait bonus on Disable Device checks made to open locks, Strength checks made to break chains or bars in order to free slaves, and combat maneuver checks made to sunder chains or bars in order to free slaves.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-confidante-to-the-oppressed"><Link to="/trait/confidante_to_the_oppressed">Confidante to the Oppressed</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link><br/>Others recognize that you are filled with the Andoren spirit of liberty and equality. You gain a +2 trait bonus on Diplomacy checks to improve the attitude of oppressed, enslaved, or imprisoned subjects, and unless they have reason to distrust you, their starting attitude toward you is at least indifferent, if not better.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-equality-for-all"><Link to="/trait/equality_for_all">Equality for All</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>Even when facing foes much larger than yourself, you still embody the Andoran ethos of liberty. You gain a +2 trait bonus to your CMB and your CMD when facing opponents who are at least two sizes larger than you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-eye-of-the-falcon"><Link to="/trait/eye_of_the_falcon">Eye of the Falcon</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link><br/>You have a way of seeing right to the heart of things. You gain a +1 trait bonus on saving throws against illusion (phantasm) spells and a +1 trait bonus on Sense Motive checks to know when you are being lied to, so long as you are face to face with the speaker in question.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-fight-for-liberty"><Link to="/trait/fight_for_liberty">Fight for Liberty</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You inspire slaves to fight for freedom with a rousing battle cry. As a standard action, you may make a rallying cry with a DC 15 Perform (oratory) check. On a successful check, any unarmed ally within 30 feet who is able to hear you gains a +2 trait bonus on attack rolls with improvised weapons and unarmed strikes. This bonus lasts for 1 round per level.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-freed-slave-andoran"><Link to="/trait/freed_slave_andoran">Freed Slave (Andoran)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You were either born or sold into slavery, but were freed by Andoren abolitionists. Your strong will helped you persevere in captivity, and gave you strength to start again from nothing in your new life in Andoran. You gain a +1 trait bonus on Will saves.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-freedom-fighter-andoran"><Link to="/trait/freedom_fighter_andoran">Freedom Fighter (Andoran)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You've developed a reputation as a privateer who fights for freedom. You gain a +2 trait bonus on Diplomacy checks. This bonus becomes a -2 penalty when dealing with slavers or those who support the slave trade. Diplomacy becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-kobolds-neighbor"><Link to="/trait/kobolds_neighbor">Kobold's Neighbor</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link><br/>You grew up in wilderness where kobolds make their homes. You learned early on how to find traps before they find you, how to disable them, and when you should just walk away. You gain a +2 trait bonus to Perception checks to discover traps and a +1 trait bonus to Disable Device checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-pretend-pirate"><Link to="/trait/pretend_pirate">Pretend Pirate</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You enjoy luring slave ships to you. Sometimes you run a pirate flag to lull criminals into a false sense of security; other times you disguise yourself as a merchant ship. You gain a +2 bonus on Disguise checks made to disguise yourself as a pirate or merchant sailor. In addition, you can take 5 minutes to alter your ship's appearance to add +2 to the DC of any check made to identify your ship's allegiance or purpose.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-prismati-player"><Link to="/trait/prismati_player">Prismati Player</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Andoran</p>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link><br/>You've grown up playing the confusing game of prismati and throw stones with accuracy and ease. You gain a +1 trait bonus on attack rolls with fist-sized rocks or similarly shaped objects, and a +1 trait bonus on <Link to="/rule/concentration">concentration</Link> checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-bellis-axe-master"><Link to="/trait/bellis_axe_master">Bellis Axe Master</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bellis</p>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link><br/>No one knows how to swing an axe better than a Bellisian! You gain a +2 trait bonus on all rolls made to confirm critical hits with axes (battle axe, hand axe, or greataxe).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-bellis-honey-harvester"><Link to="/trait/bellis_honey_harvester">Bellis Honey Harvester</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bellis</p>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link><br/>Your frequent exposure to bees - and their stings - makes all such creatures seem more like nuisances than actual threats. You gain DR 3/- against damage dealt by swarms and a +1 trait bonus on saving throws against distraction and poison from swarms.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-bellis-log-roller"><Link to="/trait/bellis_log_roller">Bellis Log Roller</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bellis</p>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link><br/>The time you spent leaping between slippery logs as they whirled down the Sellen River taught you how to keep your footing. You gain a +1 trait bonus on Acrobatics checks and a +1 trait bonus to your CMB when attempting to resist trip attacks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-carpenden-lobber"><Link to="/trait/carpenden_lobber">Carpenden Lobber</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Carpenden</p>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link><br/>Your regular participation in the moonmelon festival has made you wickedly effective at hurling harmless objects. You gain a +2 trait bonus on attack rolls when throwing items that do not deal normal hit point damage (such as weapons that deal nonlethal damage or items such as tanglefoot bags and thunderstones).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-carpenden-roof-runner"><Link to="/trait/carpenden_roof_runner">Carpenden Roof Runner</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Carpenden</p>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link><br/>Your childhood playing atop Carpenden's buildings has given you a remarkable head for heights. You gain a +2 trait bonus on Acrobatics checks made when you are at least 20 feet above the ground.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-accustomed-to-trickery"><Link to="/trait/accustomed_to_trickery">Accustomed to Trickery</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darkmoon Wood</p>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link><br/>You have been exposed to fey magic and know tricks to avoid it. Once per day, when you fail a saving throw against a fey's spell-like or supernatural ability, you may reroll the save. You must take the second result, even if it is worse.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-oregent-desperation"><Link to="/trait/oregent_desperation">Oregent Desperation</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Oregent</p>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link><br/>Your instinct to survive easily overpowers your intellect, and you consider this a more than fair trade. Once per day you can improve your condition from dying to disabled by taking 4 points of Intelligence damage.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-oregent-timing"><Link to="/trait/oregent_timing">Oregent Timing</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Oregent</p>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link><br/>After years of soul-numbing obedience to the schedules of others, you find synchronizing your actions with an ally second nature. Once per day when you take a readied action in combat, you gain a +3 trait bonus on the d20 roll for that action if it was triggered by an ally's action.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-oregent-vandal"><Link to="/trait/oregent_vandal">Oregent Vandal</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Oregent</p>
<p><strong>Sources</strong> <Link to="/source/andoran_spirit_of_liberty">Andoran, Spirit of Liberty</Link><br/>You find it quite easy to apply your carefully honed instincts for building and repairing to destruction instead. You gain a +2 trait bonus on damage rolls made against targets with hardness. This bonus does not apply to attacks that ignore hardness.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-devotee-of-kalistrade"><Link to="/trait/devotee_of_kalistrade">Devotee of Kalistrade</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Druma</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>As an adherent of the <Link to="/rule/prophecies_of_kalistrade">Prophecies of Kalistrade</Link>, you understand the importance of a good deal. You gain a +1 trait bonus on Appraise checks, and a +1 trait bonus on Bluff checks when trying to make a deal with nonbelievers.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-prophet-of-burrows"><Link to="/trait/prophet_of_burrows">Prophet of Burrows</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Druma<br/><strong>Requirements:</strong> Ratfolk</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast</Link><br/>While you might not be a practicing follower of the <Link to="/rule/prophecies_of_kalistrade">Prophecies of Kalistrade</Link>, you value human coin more than most ratfolk do and have taken the mercantile practices of the Prophecies to heart. Whenever you roll a skill check to earn money, increase the amount of money that you earn by 5%.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-purchased-loyalty"><Link to="/trait/purchased_loyalty">Purchased Loyalty</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Druma</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>As a member of Druma's Mercenary League, you are utterly loyal to the holder of your contract-at least until it expires. Once per day, when protecting someone who has bought your services, you may roll twice when making a Will save against charm effects and take the better result.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-evident-supporter"><Link to="/trait/evident_supporter">Evident Supporter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Galt</p>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link><br/>You know how best to appear supportive of the current regime despite the vagaries of a shifting government. The Sense Motive DC needed for a city guard, a politician, or other governmental functionary in a large town or larger settlement to gain a hunch about your trustworthiness is 25 (instead of 20). On a failed check, you're seen as trustworthy regardless of the situation.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-inspiring-speaker"><Link to="/trait/inspiring_speaker">Inspiring Speaker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Galt</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have learned the arts of oratory, and know how to speak to crowds to rile them up or to calm them down. You gain a +1 trait bonus on Bluff and Diplomacy checks when addressing crowds of 10 people or more.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-rabble-rebel"><Link to="/trait/rabble_rebel">Rabble Rebel</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Galt<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>Your time spent amid angry mobs has taught you exactly how to use crowds of people to distract your opponents. If you have at least three allies threatening your opponent, you gain a +2 bonus on Bluff checks to feint him and a +2 bonus on Sleight of Hand checks against him.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-silent-watcher"><Link to="/trait/silent_watcher">Silent Watcher</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Galt</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You can sense an ugly mood brewing in a crowd, and know how to dodge wrathful mobs when they seek victims for their anger. You gain a +1 trait bonus on Sense Motive checks in crowds, and a +1 trait bonus on Stealth checks in city streets.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-animal-spirit-vitality"><Link to="/trait/animal_spirit_vitality">Animal-Spirit Vitality</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>The elven druids of Kyonin taught you to commune with the natural healing powers of animals. Once per day when you cast a spell that restores hit points, you restore 1 additional hit point for every die rolled as long as a creature of the animal type is within 50 feet. You must decide to use this ability before rolling to determine the number of hit points that your spell restores.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-elven-bitterness"><Link to="/trait/elven_bitterness">Elven Bitterness</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link><br/>Only the most cunning scouts of Kyonin are selected to serve as guards along the border between the elven nation and the dreaded Tanglebriar. Most who are sent to patrol those blighted reaches go with the aid of potent magical items and under the cloak of arcane disguise. You are either close with some who have guarded the elven homeland or know of the magical defenses used by the elves against their demonic foes. When you cast an enchantment spell on a chaotic evil outsider, the DC of that spell is increased by 2.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-iadaran-illusionist"><Link to="/trait/iadaran_illusionist">Iadaran Illusionist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/elves_of_golarion">Elves of Golarion</Link><br/>You have lived in Iadara for so long that you are very familiar with illusions. You gain a +1 trait bonus on caster level checks with illusion spells and a +1 trait bonus on Will saves to disbelieve illusions.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-kyonin-gatekeeper"><Link to="/trait/kyonin_gatekeeper">Kyonin Gatekeeper</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin<br/><strong>Requirements:</strong> Elf</p>
<p><strong>Sources</strong> <Link to="/source/elves_of_golarion">Elves of Golarion</Link><br/>You helped maintain the elf gates and are familiar with the operation of teleportation magic. You gain a +1 trait bonus on Spellcraft checks to identify teleportation magic and a +1 trait bonus to caster level checks when casting teleportation spells. You know the proper commands to operate a particular elf gate (most likely an often-used elf gate, but at the GM's discretion it may be a less popular or out-of-the-way elf gate).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-tanglebriar-guerrilla"><Link to="/trait/tanglebriar_guerrilla">Tanglebriar Guerrilla</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes</Link><br/>Your campaign against Treerazer has endeared you to Kyonin's rangers, who have taught you their ways. When you gain this trait, select one ranger trap that doesn't deal ability or hit point damage. You can use this trap once per day within a forest. The DC for your trap is equal to 10 + half your character level + your Wisdom modifier (minimum +0), and it lasts for 1 day. If you are not a ranger, you can set only extraordinary traps with this feat; like all extraordinary ranger traps, this decreases the trap DC by 2.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-treerazers-bane"><Link to="/trait/treerazers_bane">Treerazer's Bane</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/elves_of_golarion">Elves of Golarion</Link><br/>Having fought in many battles against the demon Treerazer, you have learned the best ways to kill the various creatures under his control. You gain a +2 trait bonus on weapon damage against demons, evil fey, and plants and animals corrupted by evil.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-weed-resistance"><Link to="/trait/weed_resistance">Weed Resistance</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kyonin</p>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>You have learned how to keep your flesh out of the way of the toxic thorns and vines that are often prevalent in verdant lands. You gain a +3 trait bonus on saving throws against poison and disease abilities and effects inflicted by creatures of the plant type (such as a basidirond's spores).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-expert-smuggler"><Link to="/trait/expert_smuggler">Expert Smuggler</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Erages</p>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion</Link><br/>Years of smuggling and other unsavory work have trained you to hide your assets even when being actively searched. Other creatures never gain the +4 bonus on their Perception checks (opposed by your Sleight of Hand check) while frisking you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-spell-duel-prodigy"><Link to="/trait/spell_duel_prodigy">Spell Duel Prodigy</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Erages</p>
<p><strong>Sources</strong> <Link to="/source/bastards_of_golarion">Bastards of Golarion</Link><br/>You've participated in many spell duels during your time at Erages Academy, and You've developed a keen talent for identifying magical arts. You gain a +2 trait bonus on Spellcraft checks to identify a spell as it is being cast and on dispel checks to counterspell a spell.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-chivalrous"><Link to="/trait/chivalrous">Chivalrous</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link><br/>You were raised on tales of heroic knights and benevolent wizards from Taldor's Golden Age, and try to emulate their great deeds. You gain a +1 trait bonus on Diplomacy and Knowledge (history) checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-lions-audacity"><Link to="/trait/lions_audacity">Lion's Audacity</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>You attack life with the ferocity of a charging lion and inspire others with your audacious deeds. Once per day when you make a charge attack, you can inspire allies within 30 feet. They gain an additional +2 trait bonus on attack and damage rolls when they make a charge attack before the beginning of your next turn.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-militia-veteran"><Link to="/trait/militia_veteran">Militia Veteran</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor or any town or village</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link><br/>Your first job was serving in a civilian militia in your hometown. The skills you learned through daily drilling and protecting your fellow townsfolk gave you special insight into military life. Select one of the following skills: Profession (soldier), Ride, or Survival. You gain a +1 trait bonus on checks with that skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-narrows-survivor"><Link to="/trait/narrows_survivor">Narrows Survivor</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p><strong>Sources</strong> <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link><br/>You spent your childhood in the infamous Narrows district of Oppara. Years of living in violent squalor have sharpened your senses and given you an ardent distrust of humanity. You gain a +1 trait bonus to Initiative and Sense Motive checks. Sense Motive is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-poison-connoisseur"><Link to="/trait/poison_connoisseur">Poison Connoisseur</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>When the ceaseless bickering and elaborate posturing of Taldan politics proves ineffective, it is not unheard of for the nobility of Taldor to turn to poison to solve their problems, and therefore many are taught to identify the telltale signs of commonly used toxins. You gain a +2 trait bonus on saving throws against ingested poisons. Additionally, you can cast <Link to="/spell/detect_poison">detect poison</Link> as a spell-like ability once per day, using your character level as your caster level.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-pomp-and-pageantry"><Link to="/trait/pomp_and_pageantry">Pomp and Pageantry</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>Though others think you merely waste time, you know that those extra flourishes and ceremonial touches actually make your work just that much better. You gain a +1 trait bonus on Acrobatics, Diplomacy, Handle Animal, Intimidate, Perform, and Ride checks with class skills if you spend twice as long as it normally takes to make that check.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-precocious-spellcaster"><Link to="/trait/precocious_spellcaster">Precocious Spellcaster</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p><strong>Sources</strong> <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link><br/>Before you even began your training as a spellcaster, you spent a great deal of time studying cantrips and simple spells on your own. Because of this, you developed some innate magical abilities without any outside guidance. Select one cantrip and one 1st-level spell; when you cast these spells, they function at one caster level higher than your actual caster level.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_east_avistan-wealthy-dabbler"><Link to="/trait/wealthy_dabbler">Wealthy Dabbler</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Taldor</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link><br/>You study magic at one of Taldor's many social clubs, wowing your friends with your expertise in the simplest of magical exploits. Select two non-harmful arcane cantrips. You can cast these two cantrips once per day each (caster level 1st). If you have levels in a class that can cast these cantrips, your caster level for these cantrips is equal to that class level.</p>
</IonLabel></IonItem></IonList>};
const _traits_south_west_avistan = {title: "Regional Traits: Southwestern Avistan", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-aspiring-hellknight"><Link to="/trait/aspiring_hellknight">Aspiring Hellknight</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>Your family has a long tradition of service in the <Link to="/rule/hellknights">Hellknights</Link>, and your strict upbringing and training have given you a forceful aura of command. You gain a +1 trait bonus on Intimidate checks, and Intimidate is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-bellflower-tiller"><Link to="/trait/bellflower_tiller">Bellflower Tiller</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p><strong>Sources</strong> <Link to="/source/faction_guide">Faction Guide</Link><br/>You are a tiller in the secretive <Link to="/rule/bellflower_network">Bellflower Network</Link> in Cheliax and carefully move slaves from one hideout to the next. You gain a +5 trait bonus on all Survival skill checks made to get along in the wild, travel in severe weather, keep from getting lost, or predict the weather.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-chelish-guerrilla"><Link to="/trait/chelish_guerrilla">Chelish Guerrilla</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook</Link><br/>In overthrowing House Thrune, you've spent many years training to face the diabolist nobles and the devils they bind. You gain a +2 trait bonus on Knowledge checks to identify devils (and their special powers and weaknesses) and a +1 trait bonus on weapon damage rolls against devils.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-clumsy-slave"><Link to="/trait/clumsy_slave">Clumsy Slave</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax or Katapesh<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>As a former slave, you learned how to conceal your malice toward your owner behind a facade of clumsiness. The first time you attack someone with an attack that deals nonlethal damage, your target must make a Sense Motive opposed by your Bluff check minus the damage dealt to realize you actually intended to harm him; failure means he believe the injury was an accident on your part instead (though he may still want to punish you for it).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-cold-heart"><Link to="/trait/cold_heart">Cold Heart</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link><br/>You gain a +2 trait bonus on saving throws against spells and effects with the emotion descriptor.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-iron-mind"><Link to="/trait/iron_mind">Iron Mind</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p><strong>Sources</strong> <Link to="/source/knights_of_the_inner_sea">Knights of the Inner Sea</Link><br/>You gain a +2 trait bonus on saving throws against spells and effects that would reduce your Intelligence score or cause you to forget something.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-prestigious-healer"><Link to="/trait/prestigious_healer">Prestigious Healer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Once per day as an immediate action when you cast a spell of the healing subschool, you can attempt a Diplomacy check to improve the attitude of your target or anyone within 30 feet who can see you before the end of your next turn. You gain a +2 trait bonus on this check.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-secret-revolutionary"><Link to="/trait/secret_revolutionary">Secret Revolutionary</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You seek to return Cheliax to its heyday before the rise of the House of the Thrune. You have trained yourself to resist any questioning or torture should you ever be caught. You gain a +1 trait bonus on Will saves against mind-affecting effects, and on Fortitude saves against drugs or poisons.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-social-slaver"><Link to="/trait/social_slaver">Social Slaver</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax</p>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link><br/>Your upbringing has accustomed you to commanding those you deem inferior. You gain a +2 trait bonus on Intimidate checks against creatures one or more size categories smaller than yourself. The DC of compulsion spells cast by you against smaller creatures increases by 1.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-cliff-jumper"><Link to="/trait/cliff_jumper">Cliff Jumper</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cliffs of Fury</p>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils</Link><br/>You spent your early years exploring and foraging along the coastal cliffs. You gain a +1 trait bonus on Acrobatics and Climb checks, and on Reflex saves to avoid falling.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-egorian-school-apprentice"><Link to="/trait/egorian_school_apprentice">Egorian School Apprentice</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Egorian</p>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils</Link><br/>You studied under one of the masters of the Egorian School style of architecture. You gain a +3 trait bonus on Knowledge (engineering) checks and a +2 trait bonus on Perception checks to find secret doors or traps in buildings built in the Egorian School style.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-bounty-hunter"><Link to="/trait/bounty_hunter">Bounty Hunter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have made it your mission to help bring the bandits of Isger to justice. You gain a +1 trait bonus on Survival checks to find or follow tracks, and a +1 trait bonus on Perception checks to avoid being surprised.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-greenskin-stalker"><Link to="/trait/greenskin_stalker">Greenskin Stalker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger, River Kingdoms, or Varisia</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>You're a member of the Greenskin Stalkers. Due to your affiliation with this brotherhood of goblin slayers, you've learned to think and act like a goblin, as disturbing as that sounds. You receive a +1 trait bonus on Bluff, Knowledge, Perception, Sense Motive, and Survival checks against or concerning goblinoids. You can also attempt Knowledge checks concerning goblinoids untrained.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-isger-fixer"><Link to="/trait/isger_fixer">Isger Fixer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>Everyone in Isger knows how to make do with substandard equipment, and you can improvise tools and materials in order to keep a damaged object working for just a little bit longer. Once per day, you can tinker with a broken object to allow anyone who uses it to ignore the penalties for its broken condition for 24 hours (this does not affect the object's hit points). At the end of this time, it regains the broken condition (but you can use this trait on it over and over again).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-isgeri-orphan"><Link to="/trait/isgeri_orphan">Isgeri Orphan</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You grew up in one of the many Asmodean orphanages that dot the Isgeri countryside. Whether or not you took to their teachings, your strict indoctrination at the hands of the "devil nuns" has toughened your body to punishment. You gain a +1 trait bonus on Fortitude saves.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-scion-of-goblinblood"><Link to="/trait/scion_of_goblinblood">Scion of Goblinblood</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger<br/><strong>Requirements:</strong> Goblin</p>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion</Link><br/>The fury of the Goblinblood Wars still courses through your veins. Whenever you're within 60 feet of an enemy hobgoblin, you gain a +1 trait bonus on all weapon damage rolls.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-wharf-rat"><Link to="/trait/wharf_rat">Wharf Rat</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Ostenso</p>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils</Link><br/>You may never have been on a boat larger than a garbage scow, but you've been helping them dock all your life. You gain a +2 trait bonus on skill checks involving climbing and rope use, and a +4 trait bonus on Appraise checks to determine the value of large quantities of bulk goods without opening their containers.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-dump-salvager"><Link to="/trait/dump_salvager">Dump Salvager</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Westcrown</p>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils</Link><br/>You grew up in or around Westcrown's rubbish-strewn shores and spent your spare time digging through trash looking for things worth selling. You gain a +3 trait bonus on Perception checks to search for concealed items.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-whisper-woods-hunter"><Link to="/trait/whisper_woods_hunter">Whisper Woods Hunter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Whisper Woods</p>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils</Link><br/>Your family prepared you for a life of evading or destroying fiendish creatures. You gain a +2 trait bonus on Survival checks to track evil outsiders and a +2 trait bonus on initiative checks when you know your opponent is an evil outsider.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-well-bred"><Link to="/trait/well_bred">Well Bred</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Hermea</p>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link><br/>You are the product of generations of selective breeding, organized by the gold dragon Mengkare. Your education is top-notch, and you have a broad base of knowledge. Unfortunately, the isolation of Hermea has also made you slightly naive. You gain a +1 trait bonus on Knowledge (history) and Knowledge (religion) checks but take a -1 penalty on all Sense Motive checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-imperial-soldier"><Link to="/trait/imperial_soldier">Imperial Soldier</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Molthune</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You've served in the Imperial Army of Molthune. Choose one of the following skills: Heal, Intimidate, or Ride. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-legalistic-liberation"><Link to="/trait/legalistic_liberation">Legalistic Liberation</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Molthune or Osirion<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>You followed - or some might say exploited - the rules and earned your freedom by finding the loopholes within your homeland's labyrinthine codes regulating slavery and indentured servitude. You gain a +1 bonus on all Knowledge checks to find a legitimate way to avoid, negate, or escape an existing obligation.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-signaler"><Link to="/trait/signaler">Signaler</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Molthune</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>By watching Imperial troops, you know how to use flags, smoke signals, and other methods to send secret messages, and gain a +5 trait bonus on Bluff checks to receive secret messages and a +5 trait bonus on Sense Motive checks to intercept messages.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-dusk-dancer"><Link to="/trait/dusk_dancer">Dusk Dancer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>Growing up in shadowy Nidal has given you the confidence to avoid hazards which you can barely see. You gain a +2 trait bonus on Reflex saves in dim light or darkness.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-nidalese-shadowcaster"><Link to="/trait/nidalese_shadowcaster">Nidalese Shadowcaster</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have studied with the feared shadowcasters of Nidal. Choose one spell with the shadow descriptor - from this point on, whenever you cast this spell, its effect manifest at +1 caster level.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-shadow-dissident"><Link to="/trait/shadow_dissident">Shadow Dissident</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook</Link><br/>Lifelong encounters with conjured shadows have made you especially adept at piercing their dark veils. You gain a +2 trait bonus on saving throws against spells and effects with the shadow descriptor.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-shadow-shaman"><Link to="/trait/shadow_shaman">Shadow Shaman</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>Shamans in the shadowy kingdom of Nidal learn to speak with the spirits that live in shadow. Add silent image and blur to your shaman spell list as 1st- and 2nd-level spells, respectively.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-shadowsight"><Link to="/trait/shadowsight">Shadowsight</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link><br/>Your people's ancient compact with Zon-Kuthon manifests strongly in you. While the darkness remains fearsome, you can at least see what lurks there. As a swift action once per day, your eyes can pierce the surrounding darkness-you gain the benefit of low-light vision for a number of rounds equal to your level.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-unflinching-faith"><Link to="/trait/unflinching_faith">Unflinching Faith</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link><br/>Numerous expeditions to accursed regions like Nidal's Finder's Gulch have reinforced your already steadfast faith. Once per day, you may reroll a Will saving throw made against an attack or effect that originates from an undead creature. You must decide to use this trait after the first saving throw is rolled, but before the results are revealed. You must take the result of the second roll, even if it is lower.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_south_west_avistan-uskwood-hunter"><Link to="/trait/uskwood_hunter">Uskwood Hunter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nidal</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have served the Umbral Court, discreetly following interlopers through the twilit city streets of Pangolais to pinpoint their locations for the authorities. You gain a +1 trait bonus on Stealth checks, and Stealth is always a class skill for you.</p>
</IonLabel></IonItem></IonList>};
const _traits_darklands = {title: "Regional Traits: Darklands", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-ghoulish-affinity"><Link to="/trait/ghoulish_affinity">Ghoulish Affinity</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link><br/>Ever since you recovered from ghoul fever, the scars on your arms and hands itch whenever one of these vile creatures is nearby. You gain a +2 trait bonus on Perception checks to notice undead disguised as living creatures, and a +2 trait bonus on Fortitude saves against diseases and poisons inflicted by undead.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-gravelwalker"><Link to="/trait/gravelwalker">Gravelwalker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link><br/>Having grown up navigating rockslides and picking your way through partially collapsed tunnels, you are able to determine the most stable path across difficult terrain caused by rubble or other debris. You can move normally through such obstructed spaces, and can run or charge though them with a successful Acrobatics check.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-grit-goggles"><Link to="/trait/grit_goggles">Grit Goggles</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link><br/>Exposure to the constant hazards of airborne particles (such as during a sandstorm or cave-in) has made your eyes less susceptible to irritants, such as sand, dust, and even liquids and gases. You gain a +2 trait bonus against being blinded by foreign objects (such as from a Dirty Trick combat maneuver) and you halve any reductions in visibility from the environment (such as from certain storms) and their corresponding penalties. For example, if you were in a sandstorm that normally reduces visibility to 25 feet and imparts a -4 penalty on Perception checks, you reduce visibility to 50 feet and take only a -2 penalty on Perception checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-iron-lungs"><Link to="/trait/iron_lungs">Iron Lungs</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link><br/>Due to the constant intrusion of marsh gases seeping into the tunnels and chambers of your lair, you can <Link to="/misc/hold_your_breath">hold your breath</Link> for twice as long and gain a +2 trait bonus on saving throws against the effects of inhaled poisons.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-snowstride"><Link to="/trait/snowstride">Snowstride</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link><br/>The wide stance and sure footing you developed while traipsing over ice-covered rock and frozen earth provides you with a +1 trait bonus on Acrobatics checks made on slippery surfaces and enables you to trip or bull rush opponents two size categories larger than you instead of just one.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-stream-nomad"><Link to="/trait/stream_nomad">Stream Nomad</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link><br/>Digging tunnels near a body of rushing water has taught you how to use water as a means of travel and escape. Others whisper that you must have been born with webbed feet. You gain a +1 trait bonus on Swim checks, and Swim is always a class skill for you. You increase the speed of any raft, barge, keelboat, or rowboat you pilot by 4 miles per day (1/2 mile per hour).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-suck-in-your-gut"><Link to="/trait/suck_in_your_gut">Suck in Your Gut</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link><br/>Because of the frequent need to move through the tight tunnels and other narrow spaces surrounding your tribe's lair, you're able to move normally when squeezing and take only a -2 penalty on attack rolls and to AC.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-trap-savvy"><Link to="/trait/trap_savvy">Trap Savvy</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands</p>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link><br/>Growing up in a dangerous area, you were constantly surrounded by traps that had been set up to defend your lair from intruders. Sometimes these dangers were so densely packed that you couldn't go more than a couple feet down a tunnel without encountering a new way to die. You gain a +1 trait bonus on Craft (traps) checks, and gain a +1 bonus to AC against attacks by traps or on saving throws against effects created by traps.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-cavern-survivor"><Link to="/trait/cavern_survivor">Cavern Survivor</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nar-Voth</p>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands</Link><br/>You've regularly traversed Nar-Voth and know how to subsist in that lightless realm better than most surface dwellers. You gain a +2 trait bonus on Survival checks to survive in a subterranean wilderness, and Survival is a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-darklands-delver"><Link to="/trait/darklands_delver">Darklands Delver</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands beneath Tian Xia</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You are familiar with the byways and passages of Tian Xia's underworld. You gain a +1 trait bonus on Knowledge (dungeoneering) checks, and a +1 trait bonus on Survival checks made in the Darklands. One of these skills becomes class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_darklands-slayer-of-the-deep"><Link to="/trait/slayer_of_the_deep">Slayer of the Deep</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Darklands beneath Tian Xia</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You have hunted monsters throughout the Darklands and know how to take advantage of their weaknesses. You gain a +1 trait bonus on damage rolls made against creatures of the aberration type.</p>
</IonLabel></IonItem></IonList>};
const _traits_extraplanar = {title: "Regional Traits: Extraplanar", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-planar-negotiator-dhh"><Link to="/trait/planar_negotiator_dhh">Planar Negotiator (DHH)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Abyss</p>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link><br/>You are used to dealing with outsiders that would fluster a less experienced negotiator. When dealing with an outsider within one step of your alignment, you gain a +1 trait bonus on Diplomacy and Sense Motive checks. Increase these bonuses to +2 if you and the outsider worship the same deity.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-true-name-caller"><Link to="/trait/true_name_caller">True Name Caller</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Abyss</p>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link><br/>You are skilled at discovering the true names of outsiders. Choose a plane other than the Material Plane. When attempting to discover the true name of an outsider from the chosen plane, you halve the amount of research time required and gain a +4 trait bonus on the Knowledge (planes) check made to learn the outsider's name.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-airship-captain"><Link to="/trait/airship_captain">Airship Captain</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Air</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>Your years of piloting airships on the Plane of Air, dodging angry mephits and protecting your passengers from the depredations of capricious elementals, have taught you how to expertly command your vessel, as well as how to arrest yourself even in the midst of the most turbulent planar storms. You gain a +2 trait bonus on Wisdom checks to move in a plane with subjective directional gravity (see the <Link to="/rule/planar_traits">planar rules</Link>) and a +2 trait bonus on driving checks (see the <Link to="/rule/full_vehicle_rules">vehicle rules</Link>).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-armun-kelisk-scholar"><Link to="/trait/armun_kelisk_scholar">Armun Kelisk Scholar</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Air</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>During your time on the Plane of Air, you visited the libraries of Armun Kelisk frequently and voraciously read the tomes therein. You gain a +1 trait bonus on Knowledge (planes) checks and checks made with one other Knowledge skill of your choice. This bonus increases to +3 when used to identify a creature with the air subtype. Knowledge (planes) becomes a class skill for you, and your bonus language options at 1st level include Auran. This choice is in addition to the bonus languages available to the character because of her race.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-agent-of-the-sultana"><Link to="/trait/agent_of_the_sultana">Agent of the Sultana</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Earth</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>You have learned many adventuring skills - as well as hatred for efreet - during your years of military service to Sultana Ashadieeyah bint Khalid, ruler of the Opaline Vault on the Plane of Earth. You gain a +2 trait bonus on Disable Device checks to disarm any traps that you know deal fire damage, and you gain a +2 trait bonus on attack rolls to confirm critical hits against creatures with the fire subtype.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-channel-the-earth"><Link to="/trait/channel_the_earth">Channel the Earth</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Earth</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>Perhaps you worship the Elemental Lord of Earth, or perhaps you have gleaned your fated powers via some other means of interacting with the Eternal Delve. Your divine powers are infused with the elemental powers of the Plane of Earth. Whenever you channel positive energy to heal living creatures, affected targets gain a +2 profane bonus to CMD to resist bull rush, reposition, and trip combat maneuvers. Alternately, if you channel negative energy to harm living creatures, affected targets take a -2 penalty to CMD against such combat maneuvers. This effect lasts 1 round.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-fiery-dominance"><Link to="/trait/fiery_dominance">Fiery Dominance</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Fire</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>Raised among the efreet of the Plane of Fire, you developed a similarly assured sense of superiority over people from other backgrounds. You gain a +1 trait bonus on Intimidate checks against humanoids of a subtype different from your own (or all non-human humanoids, if you are not a humanoid), and the DC for such creatures to demoralize you with Intimidate is 2 higher than usual.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-thoughtful-wish-maker"><Link to="/trait/thoughtful_wish_maker">Thoughtful Wish-Maker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Fire</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>You are well acquainted with the many ways words can be twisted. You gain a +2 trait bonus on Sense Motive checks. Furthermore, if you succeed at a DC 25 Sense Motive check prior to making any wish granted by an outsider, you become aware of your wish's potential pitfalls. If you succeed at this check by 5 or more, you figure out how to word your wish in such a way that your words are not twisted.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-betrayed-ex-noble"><Link to="/trait/betrayed_ex_noble">Betrayed Ex-Noble</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> City of Brass</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>You were born a noble in the City of Brass, but were unjustly stripped of your title or exiled. Now, your ire prevents you from brooking any further insult unto your already disgraced name. Whenever an enemy attempts to feint against you in combat, the DC to do so is equal to 10 + your base attack bonus + your Wisdom modifier, or 10 + your Intimidate bonus, whichever is higher.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-solidarity"><Link to="/trait/solidarity">Solidarity</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> City of Brass</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>While enslaved in the City of Brass, you watched too many of your friends fall victim to efreet tempers. Now, you help others avoid thorny situations whenever you are able. Any time you successfully use the aid another action to help an ally succeed at a Bluff or Escape Artist check, you add a +3 bonus to this check (rather than a +2 bonus).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-aquatic-survivalist"><Link to="/trait/aquatic_survivalist">Aquatic Survivalist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Water</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>For whatever reason, you spent much of your formative years fighting to keep yourself alive amid the fearsome creatures that inhabit the infinite oceans of the Plane of Water, and you learned how to stay hidden even against predators with unusual senses. You gain a +2 trait bonus on Stealth checks while underwater. Once per day, you can attempt a Stealth check to hide in plain sight (as the ranger class feature of the same name) while underwater. This is only effective against creatures that rely on blindsense, blindsight, or tremorsense. Creatures with other senses perceive you normally.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-vialesk-historian"><Link to="/trait/vialesk_historian">Vialesk Historian</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Plane of Water</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>Your long years of studious research into the drifting trade city of Vialesk, a neutral ground for planar travelers on the Elemental Plane of Water, has made you an expert on all manner of aquatic creatures. You gain a +2 trait bonus on Knowledge (planes) checks to identify outsiders with the water subtype. In addition, you treat your caster level as 1 higher when casting conjuration (summoning) spells to summon outsiders with the water subtype.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_extraplanar-voices-of-solid-things"><Link to="/trait/voices_of_solid_things">Voices of Solid Things</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Witchmarket</p>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link><br/>You traveled with the Witchmarket for a time, either willingly or as a result of a bargain made by some other buyer. In your time in the Witchmarket, you learned to listen to the whispers of items as though they were living creatures, giving you clues as to their function. Choose Appraise, Craft, Disable Device, or Spellcraft. You apply your Charisma modifier on checks with that skill instead of the skill's normal ability score. That skill is a class skill for you.</p>
</IonLabel></IonItem></IonList>};
const _traits_eye_of_abendego = {title: "Regional Traits: Eye of Abendego", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-abendego-pilot"><Link to="/trait/abendego_pilot">Abendego Pilot</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Eye of Abendego<br/><strong>Requirements:</strong> Slyph</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>The howling gales of the Eye of Abendego were your lullaby as a child, and you quickly learned to anticipate the winds' danger as well as parse their song. You gain a +2 trait bonus on Profession (sailor) checks, and you treat the wind force of environmental wind effects as one step less powerful for the purposes of determining any penalties on ranged attacks and Fly checks as well as whether you would be checked or blown away.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-citizen-of-eleder"><Link to="/trait/citizen_of_eleder">Citizen of Eleder</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Eleder</p>
<p><strong>Sources</strong> <Link to="/source/sargava_the_lost_colony">Sargava, the Lost Colony</Link><br/>You live and work in Eleder. You gain a +1 trait bonus on all Knowledge (local) and Knowledge (nobility) checks regarding Eleder.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-citizen-of-kalabuto"><Link to="/trait/citizen_of_kalabuto">Citizen of Kalabuto</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kalabuto</p>
<p><strong>Sources</strong> <Link to="/source/sargava_the_lost_colony">Sargava, the Lost Colony</Link><br/>You live and work in Kalabuto. You gain a +1 trait bonus on all Knowledge (local) and Knowledge (history) checks regarding Kalabuto.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-stargazer-region"><Link to="/trait/stargazer_region">Stargazer (Region)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lirgen</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 11</Link><br/>Having spent your youth staring at the night sky, you gain a +1 trait bonus on Knowledge (arcana) and Knowledge (nature) checks. One of these skills becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-plainsman"><Link to="/trait/plainsman">Plainsman</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> M'neri Plains</p>
<p><strong>Sources</strong> <Link to="/source/sargava_the_lost_colony">Sargava, the Lost Colony</Link><br/>You live and work on the M'neri Plains. You gain a +1 trait bonus on all Knowledge (geography) and Survival checks regarding the M'neri Plains.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-cultist-lineage"><Link to="/trait/cultist_lineage">Cultist Lineage</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>Your parents were both Red Mantis assassins and your family has a long tradition of service in the <Link to="/rule/red_mantis">Red Mantis</Link> cult. Your strict, fanatical upbringing and familiarity with murder have bestowed upon you an air of confidence and menace. This grants you a +1 trait bonus on Intimidate checks. If you act during the surprise round, as a free action during that round you can draw a light weapon (or two if you have the <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link> feat).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-devilfish-diver"><Link to="/trait/devilfish_diver">Devilfish Diver</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You've swum with the devilfish along the Mediogaltian coast. You gain a +2 trait bonus on saving throws versus poison.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-dinosaur-whisperer"><Link to="/trait/dinosaur_whisperer">Dinosaur Whisperer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>After spending a month in the Mediogaltian jungle, you developed a knack for dealing with dinosaurs. You gain a +1 trait bonus on Knowledge (nature) and Survival checks concerning dinosaurs. You also gain a +1 trait bonus on <Link to="/ability/wild_empathy">wild empathy</Link> checks made to affect dinosaurs.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-monkey-goblin"><Link to="/trait/monkey_goblin">Monkey Goblin</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti<br/><strong>Requirements:</strong> Goblin</p>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion</Link><br/>You are adept at arboreal activity, and are more at home in the branches of a tree than you are on the ground. You gain a +2 trait bonus on Acrobatics and Climb checks while climbing trees.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-pirate-duelist"><Link to="/trait/pirate_duelist">Pirate Duelist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You've rubbed elbows with pirates of all stripes in Ilizmagorti's taverns and convinced a few to show off their swordfighting skills. You gain a +1 trait bonus on attacks of opportunity made with daggers, short swords, cutlasses, rapiers, scimitars, or hook hands.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-treasure-mapper"><Link to="/trait/treasure_mapper">Treasure Mapper</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mediogalti</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You've spent a great deal of time hunting down and following treasure maps-most false, but a few with legitimate information. You gain a +2 bonus on Survival or Profession (sailor) checks made to navigate using a map or chart, and one of them becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-jungle-guide"><Link to="/trait/jungle_guide">Jungle Guide</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sargava</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You've made your living outfitting and guiding expeditions deep into the Mwangi interior in search of ancient ruins and lost cities. You gain a +1 trait bonus on Handle Animal checks, and a +1 trait bonus on Survival checks in jungle terrain. One of these skills is a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-sargavan-guard"><Link to="/trait/sargavan_guard">Sargavan Guard</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sargava</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You served in the Sargavan Guard, either as a colonial sub-praetor or as a native Mwangi regular, and have grown accustomed to marching in hot temperatures while wearing armor. When you wear armor of any sort, reduce the armor check penalty by 1, to a minimum penalty of 0.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-flotsam"><Link to="/trait/flotsam">Flotsam</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link><br/>You were one of only a few that survived the destruction of the merchant vessel Vantage. Your crew was more than able to hold off the blundering pirate attackers, but their red dragon ally proved too much for your defenses. As you watched the sharks and eels feast on the bodies of your fallen comrades, you vowed to see Aashaq slain. You gain a +2 bonus on Reflex saves against spells and effects with the fire descriptor.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-goblin-pirate"><Link to="/trait/goblin_pirate">Goblin Pirate</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles<br/><strong>Requirements:</strong> Goblin</p>
<p><strong>Sources</strong> <Link to="/source/goblins_of_golarion">Goblins of Golarion</Link><br/>Although you might prefer life on board a ship, you often end up in the water for some odd reason. You gain a +1 trait bonus on Profession (sailor) and Swim checks, and Swim is always a class skill for you. You might also have a peg leg or a hook for a hand, but that's not so helpful.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-home-port"><Link to="/trait/home_port">Home Port</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You have a fondness for a particular port, and the people who live and do business there return the sentiment. You gain a +2 trait bonus on Diplomacy checks to gather information in your chosen home port.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-hurricane-savvy"><Link to="/trait/hurricane_savvy">Hurricane Savvy</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You are used to sailing in the terrible winds that roll out from the Eye of Abendego, and can apply the skills you've learned to any storm. You treat wind effects as one wind force category less than they actually are, both for any personal checks you must make and for any you make to captain or steer a ship.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-narrow-escape"><Link to="/trait/narrow_escape">Narrow Escape</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You were captured by kuru cannibals and nearly devoured in a sacrificial ritual. At the last second you wriggled free from your bonds and escaped into the jungle. Your narrow escape has left you with a paranoid fear of capture. You secretly conduct regular sessions in which you slip out of different types of knots. You gain a +1 trait bonus on Escape Artist checks, and Escape Artist becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-scourge-of-the-seas"><Link to="/trait/scourge_of_the_seas">Scourge of the Seas</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>You have long appreciated the flamboyance and versatility of the whip, both as a weapon and a tool for enforcing discipline. When you wield a whip or scourge, you gain a +1 trait bonus on Intimidate checks. Additionally, once per day when you use a whip or scourge to perform a successful disarm or trip combat maneuver against an opponent, you regain 1 point of grit or panache.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-shackles-seafarer"><Link to="/trait/shackles_seafarer">Shackles Seafarer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You're familiar with the treacherous coastlines, currents, and tides of the Shackles, and can use that knowledge anywhere. You gain a +1 trait bonus on Knowledge (nature) and Knowledge (geography) checks while on the ocean. You also gain a +1 trait bonus on Swim checks, and Swim is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-ship-aptitude"><Link to="/trait/ship_aptitude">Ship Aptitude</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You are used to crewing on many of the different types of ships that sail the Shackles. As a result, you have a knack for quickly determining the weaknesses and strengths of any ship, even ones you've never set foot on before. You gain a +1 trait bonus on Profession (sailor) checks, and Profession (sailor) becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-stormrunner"><Link to="/trait/stormrunner">Stormrunner</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have sailed on some of the roughest seas on Golarion, and have skirted the Eye of Abendego. You're accustomed to the pitch and yaw of sailing vessels, even in a storm, and gain a +2 trait bonus on Acrobatics checks to keep your footing on uneven ground or unsteady surfaces.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-sustaining-performance"><Link to="/trait/sustaining_performance">Sustaining Performance</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Shackles</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Abandoned by a traditional healer at a critical time, you improvised a tale or jokes to keep up the spirits of someone in dire health. Once per day as a standard action, you can attempt a DC 15 Perform check with an audible component (such as comedy, oratory, sing, or with any instrument) to stabilize a dying creature that can hear you within 30 feet. You can also attempt Perform checks instead of Heal checks to provide long-term care.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-abendego-spellpiercer"><Link to="/trait/abendego_spellpiercer">Abendego Spellpiercer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Sodden Lands</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have spent time in the gales of the perpetual hurricane, and can cast spells even when battered by the elements. You gain a +2 trait bonus on <Link to="/rule/concentration">concentration</Link> checks when spellcasting.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-oagan-diver"><Link to="/trait/oagan_diver">Oagan Diver</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Sodden Lands</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You know how to operate the diving bells of Oagon at the mouth of the Black Flow. You've dived the streets of sunken Lirgen yourself, and you know what to expect. You gain a +1 trait bonus on Swim checks, and Swim is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-sodden-chld"><Link to="/trait/sodden_chld">Sodden Chld</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Sodden Lands</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes</Link><br/>You spent most of your life moving through murky bogs and have grown acclimated to the terrain. You move normally through shallow bogs (as long as the terrain hasn't been magically manipulated) but are still affected by deep bogs as normal.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-star-reader"><Link to="/trait/star_reader">Star Reader</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> The Sodden Lands</p>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link><br/>You are one of the few remaining descendants of the lost civilization of Lirgen. Growing up learning of your people's history has granted you a fine understanding of celestial divination as well as a deep-seated hatred of the demon-worshiping monsters that have come to rule your ancestral lands. While under starlight, the caster level of all your divination spells is increased by 1. If the target of your spell is a demon, the caster level is increased by 2.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_eye_of_abendego-naturalist"><Link to="/trait/naturalist">Naturalist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Yamasa</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 11</Link><br/>Your ancestors taught you the importance of using what nature provides. You gain a +3 trait bonus on Survival checks when attempting to survive in the wilderness.</p>
</IonLabel></IonItem></IonList>};
const _traits_generic = {title: "Regional Traits: Generic Terrains", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-observant-archer"><Link to="/trait/observant_archer">Observant Archer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> aquatic</p>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link><br/>Growing up in an aquatic environment, where three-dimensional movement and perception were necessary, has given you keen observational skills and the ability to notice and target unusual positions with ranged attacks. You gain a +1 trait bonus on ranged attack rolls when your target is at least 10 feet above or below you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-giant-investigator"><Link to="/trait/giant_investigator">Giant Investigator</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> coastal</p>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link><br/>As a result of your attempts to understand a rare encounter with the unearthly divine magic or secretive movements of coast-dwelling giants, you have learned to carefully consider all facts related to a mystery and form deductions after taking time to mull over an unanswered question. Whenever you fail a Knowledge (local) or Knowledge (religion) check, you can attempt the check again in 24 hours with a +2 bonus to represent your careful formation of a new deduction. Additionally, you can attempt such skill checks untrained when the checks involve giants.</p>
<p>Likely Regions: Katapesh, Lands of the Linnorm Kings, Mwangi Expanse, Rahadoum, the Shackles, Varisia.</p>
<p>Likely giants: Marsh, Ocean, River, Storm, Taiga</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-sea-souled"><Link to="/trait/sea_souled">Sea-Souled</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> coastal or island</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link><br/>You are at home at sea. You receive a +1 trait bonus on Swim checks, and you can always take 10 while Swimming.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-beachcomber"><Link to="/trait/beachcomber">Beachcomber</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> coastal or river</p>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link><br/>You have a knack for finding what you need as it washes ashore. Once per week, if you spend 8 hours in a single day searching along a shoreline, you can attempt a Survival check. You find any combination of mundane objects whose value in gold pieces is less than or equal to the result of the check, in a usable (if somewhat waterlogged) condition.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-desert-child"><Link to="/trait/desert_child">Desert Child</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia, desert</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>, <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link>, <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You were born and raised in rocky deserts, and are accustomed to high temperatures. You gain a +4 trait bonus on saving throws made to resist the effects of being in hot conditions and a +1 trait bonus on saving throws against fire effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-giant-dodger"><Link to="/trait/giant_dodger">Giant Dodger</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> desert</p>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link><br/>In your youth, you were chased by giants for trespassing - or for sport - and you have learned to evade the reach of your opponents. You gain a +3 bonus on Acrobatics checks to avoid provoking an attack of opportunity when moving out of a threatened space.</p>
<p>Likely Regions: Katapesh, Osirion, Qadira, Rahadoum, Thuvia.</p>
<p>Likely giants: Cliff, Desert, River</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-sun-blasted"><Link to="/trait/sun_blasted">Sun-Blasted</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> desert</p>
<p><strong>Sources</strong> <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link><br/>Desert orcs have learnt to survive with practically nothing in the desert. You receive a +2 trait bonus on Survival checks made in a desert, and resolve all checks at becoming lost in deserts as though you had proper navigational tools (a +4 bonus). The presence of such tools does not increase your ability, however.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-windspeaker"><Link to="/trait/windspeaker">Windspeaker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> desert</p>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link><br/>You have a keen sense for weather patterns, and you always know 8 hours in advance when naturally occurring winds will reach high speeds.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-lair-snake"><Link to="/trait/lair_snake">Lair Snake</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> dragon's lair</p>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link><br/>You spent your formative years bowing and scraping in the presence of a dragon, witnessing the glory of the vast hoard... and squirreling away a few bits of coin for yourself. You gain a +1 trait bonus on Appraise checks, and your starting wealth increases by 200 gp.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-briar-bandit"><Link to="/trait/briar_bandit">Briar Bandit</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> forest</p>
<p><strong>Sources</strong> <Link to="/source/kobolds_of_golarion">Kobolds of Golarion</Link><br/>The time you've spent crawling through thorny brambles and other thick underbrush during raids and ambushes taught you how to move without disturbing the dense flora around you. When in overgrown areas, you gain a +2 trait bonus on Stealth checks and a +1 trait bonus on damage rolls with sneak attacks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-log-roller"><Link to="/trait/log_roller">Log Roller</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> forest</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>The time you spent leaping between slippery logs as they whirled down the river to market taught you how to keep your footing. You gain a +1 trait bonus on Acrobatics checks and a +1 trait bonus to your CMB when attempting to resist trip attacks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-enchanted-by-giants"><Link to="/trait/enchanted_by_giants">Enchanted by Giants</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> forest, jungle, or taiga</p>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link><br/>You are familiar with the primeval magic of forest-dwelling giants and have witnessed their close attention to the natural world around them, whether because your tribe engaged in trade with those giants or because you stumbled into their territory. The experience opened your eyes to the workings of nature and magic. You gain a +1 trait bonus on Survival checks and Spellcraft checks. You can always take 10 on Spellcraft checks to identify spell-like abilities.</p>
<p>Likely Regions: Kyonin, Lands of the Linnorm Kings, Mwangi Expanse, Nirmathas, River Kingdoms, Taldor.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-frontier-forged"><Link to="/trait/frontier_forged">Frontier-Forged</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> frontier</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link><br/>A hard life on the edge of civilization has made you resourceful but has also given you a streak of self-preservation bordering on paranoia. You receive a +1 trait bonus on Perception checks and a +1 bonus on Survival checks made to get along in the wild.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-highlander"><Link to="/trait/highlander">Highlander</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> hills or mountains</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>You were born and raised in rugged badlands or hills, and you've become something of an expert at evading the predators, monsters, and worse that haunt the highlands. You gain a +1 trait bonus on Stealth checks, and Stealth is always a class skill for you. This trait bonus increases to +2 in hilly or rocky areas.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-surefooted-ascent"><Link to="/trait/surefooted_ascent">Surefooted Ascent</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> hills or mountains</p>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link><br/>You gain a +1 trait bonus on Acrobatics and Climb checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-fruit-merchant"><Link to="/trait/fruit_merchant">Fruit Merchant</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> jungle</p>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link><br/>When bartering for mundane items like food, water, and clothing, you can purchase supplies for 10% less and sell them for 10% more.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-scrambling-servant"><Link to="/trait/scrambling_servant">Scrambling Servant</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> mountains</p>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link><br/>You were hired or captured by giants and found yourself frequently scrambling up and down giant-sized furniture or slave pit walls. As a result, you are an agile climber. You retain your Dexterity bonus to Armor Class while climbing and gain a +1 trait bonus on Climb checks.</p>
<p>Likely Regions: Osirion, Rahadoum, the Shackles, Thuvia, Varisia.</p>
<p>Likely giants: Cave, Fire, River, Slag, Storm</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-savanna-child"><Link to="/trait/savanna_child">Savanna Child</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh, plains</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>, <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link><br/>You were born and raised in central Katapesh, among the rolling savannahs that dominate the nation's interior. You spent many of your youth exploring these vast reaches, and know much of the savannah's secrets. Pick one of the following skills: Handle Animal, Knowledge (nature), or Ride. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-lost-role-model"><Link to="/trait/lost_role_model">Lost Role Model</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> settlement near a famous dungeon</p>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link><br/>As a youth, you marveled at the crusaders, spelunkers, and lore seekers who came through your town on their way to the nearby dungeon, tomb, or ruins. One such intrepid role model in particular was of great import to you. On the last day you ever saw your hero, the adventurer gave you a unique dungeon guide worth no more than 750 gp and with an accuracy modifier of no greater than +2.</p>
<p><strong>Suggestion:</strong> With the help of your GM and using the <Link to="/main/equipment_misc">example dungeon guides</Link>, construct a unique dungeon guide tied to the dungeon near where you grew up.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-swamp-recluse"><Link to="/trait/swamp_recluse">Swamp Recluse</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> swamp</p>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link><br/>You gain a +2 trait bonus on saving throws against poison, and you can safely eat raw fish and game without any effort spent cooking or cleaning them.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-river-rat"><Link to="/trait/river_rat">River Rat</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> swamp or river</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link><br/>You learned to swim right after you learned to walk. When you were a youth, a gang of river pirates put you to work swimming in nighttime rivers and canals with a dagger between your teeth so you could sever the anchor ropes of merchant vessels. You gain a +1 trait bonus on damage rolls with a dagger and a +1 trait bonus on Swim checks. Swim is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-giant-ambivalence"><Link to="/trait/giant_ambivalence">Giant Ambivalence</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> temperate highlands</p>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link><br/>You witnessed or were otherwise strongly influenced by two separate acts by giants, one of great beneficence and one of great violence. You reflexively gauge the intentions of powerful creatures in case they turn to violence. You gain a +1 trait bonus on initiative checks. You also gain a +1 trait bonus on Sense Motive checks, and a +2 trait bonus on Perception checks to not be surprised in a surprise round of combat.</p>
<p>Likely Regions: Isger, Molthune, Numeria, Realm of the Mammoth Lords, Varisia.</p>
<p>Likely giants: Cloud, Hill, River, Stone</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-chilled-by-brutality"><Link to="/trait/chilled_by_brutality">Chilled by Brutality</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> tundra</p>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link><br/>You were part of a group that was mercilessly attacked by giants of the tundra, who may have gone so far as to eat the dead and dying. After that, little can faze you, but you strongly prefer to finish fights with giants quickly to prevent anything like that from happening again. You gain a +2 trait bonus on attack rolls to confirm critical hits against giants and on saving throws against fear effects.</p>
<p>Likely Regions: Brevoy, Irrisen, Lands of the Linnorm Kings, Mendev, Realm of the Mammoth Lords.</p>
<p>Likely giants: Cloud, Frost, River, Rune, Taiga</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-sharp-eyes"><Link to="/trait/sharp_eyes">Sharp Eyes</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> tundra</p>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins</Link><br/>You are immune to the dazzled condition.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-tundra-child"><Link to="/trait/tundra_child">Tundra Child</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> tundra or other cold regions</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link><br/>You were born and raised in the cold wastes of the far north or far south, and are accustomed to low temperatures. You gain a +4 trait bonus on saving throws made to resist the effects of being in cold conditions and a +1 trait bonus on saving throws against cold effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-dungeon-dweller"><Link to="/trait/dungeon_dweller">Dungeon Dweller</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> underground</p>
<p><strong>Sources</strong> <Link to="/source/dungeoneers_handbook">Dungeoneer's Handbook</Link><br/>Not only are you competent while deep underground, you thrive in these perilous environs. Whether you were born in one of the labyrinthine tunnels that riddle the islands of the Shackles or your mysterious parental figures brought you up in the sand-ridden corridors of some forgotten Osirian pyramid, your emergence on Golarion is somehow tied to one of the world's infamous subterranean dungeons. You start with one additional language chosen from the following list: Aklo, Dark Folk, Draconic, Goblin, Necril, Orc, or Undercommon. In addition, whenever you must attempt a Survival check to avoid getting lost in a dungeon, you may roll the check twice and take the better result.</p>
<p><strong>Suggestion:</strong> Consider playing an uncommon race.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-surface-stranger"><Link to="/trait/surface_stranger">Surface Stranger</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> underground</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link><br/>You were born and raised in a subterranean home with little or no bright light. Your miss chance for <Link to="/rule/concealment">concealment</Link> or total concealment due to either mundane or magical darkness decreases by 10%. You are dazzled for 1 round when you are suddenly exposed to bright light.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-charmed-innocent"><Link to="/trait/charmed_innocent">Charmed Innocent</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link><br/>Your apparent good nature or playful charm makes nonevil creatures want to like you. Once per day, before you roll any Charisma check or Charisma-based skill check against a nonevil creature, you can roll twice and take the better result.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-cloistered-upbringing"><Link to="/trait/cloistered_upbringing">Cloistered Upbringing</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link><br/>Growing up among acolytes or monks, you were exposed to their supernatural power. You gain a +1 trait bonus on saving throws against the supernatural effects of channeled energy or abilities powered by ki, and regain 1 additional hit point when healed by supernatural effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-cultivated"><Link to="/trait/cultivated">Cultivated</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link><br/>You grew up speaking multiple <Link to="/misc/languages">languages</Link>. You learn one additional language. Additionally, when attempting a Diplomacy check to gather information using this language, you can do so in 1d6 &times; 10 minutes, rather than the normal 1d4 hours.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-cunning-liar"><Link to="/trait/cunning_liar">Cunning Liar</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link><br/>You were forced into hiding or willingly went on the run at a young age, and learned to reading others' interests to inform your lies. You can use your Intelligence or Wisdom modifier in place of your Charisma modifier on Bluff checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-diligence"><Link to="/trait/diligence">Diligence</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link><br/>You grew up helping with a family business or were mentored by an expert in some craft or profession, who taught you diligence. Select one specific Craft or Profession skill. You can take 20 with that skill in half the amount of time normally required to take 20.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-good-folk"><Link to="/trait/good_folk">Good Folk</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link><br/>People's faith in you tends to run deeper than their trust of others. You gain a +2 bonus on Charisma checks and Charisma-based skill checks with creatures that have a friendly or helpful attitude towards you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-lost-origins"><Link to="/trait/lost_origins">Lost Origins</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link><br/>You are disconnected from your heritage and do what you can to learn more about where your family is or where your people came from. Knowledge (local) is always a class skill for you, and you can always take 10 on Knowledge (local) checks, even when stress or distractions would normally prevent you from doing so.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-street-wary"><Link to="/trait/street_wary">Street Wary</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets</Link><br/>You learned to take care of yourself on the streets and know the warning signs of hostile intent. Sense Motive is always a class skill for you, and you gain a +2 trait bonus on Sense Motive checks to get a hunch.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-vagabond-child"><Link to="/trait/vagabond_child">Vagabond Child</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> urban</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/taldor_echoes_of_glory">Taldor, Echoes of Glory</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link><br/>You grew up among the outcasts and outlaws of your society, learning to forage and survive in an urban environment. Select one of the following skills: Disable Device, Escape Artist, or Sleight of Hand. You gain a +1 trait bonus on checks with that skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-ash-bane"><Link to="/trait/ash_bane">Ash Bane</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> wasteland</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes</Link><br/>You have built up a resistance to the diseases that ash giants and their vermin guardians carry. You gain a +2 trait bonus on Fortitude saving throws to resist the disease abilities of ash giants and creatures with the vermin type. In addition, you gain a +1 trait bonus on melee attack rolls against vermin.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_generic-giant-harried"><Link to="/trait/giant_harried">Giant-Harried</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> wasteland</p>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook</Link><br/>You were robbed by giants or nearly killed by a giant's prank, and the experience gave you a keen instinct for outmaneuvering bigger creatures. You gain a +1 trait bonus on combat maneuver checks against creatures larger than you and a +1 trait bonus to CMD against such creatures.</p>
<p>Likely Regions: Geb, Mana Wastes, Nex, Nidal, Numeria.</p>
<p>Likely giants: Ash, Hill, River, Shadow</p>
</IonLabel></IonItem></IonList>};
const _traits_northwest_garund = {title: "Regional Traits: Northwestern Garund", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-community-minded"><Link to="/trait/community_minded">Community-Minded</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link><br/>While some pray to the gods for mercy or prosperity, you follow a different tack-you believe in improving the lives of those around you through earnest labor and the efforts of you and your community. Your hard-earned discipline and the candor of your words affect all who bear witness. Any morale bonuses you confer upon your allies through your own abilities or spells last 2 additional rounds.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-godless-resolve"><Link to="/trait/godless_resolve">Godless Resolve</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bachuan, Rahadoum or Touvette</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Some brilliant and earnest speech or other performance inspired you to take charge of your own health rather than begging indifferent or outlawed deities for deliverance. Heal is a class skill for you, and you gain a +2 trait bonus on Heal checks to stabilize dying creatures and stop bleeding.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-justiciar"><Link to="/trait/justiciar">Justiciar</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link><br/>You are experienced in interpreting and applying legal doctrine, notably the Laws of Man, independent of any divine mandates. You gain a +1 trait bonus on Diplomacy and Knowledge (local) checks to settle disputes or arbitrate laws. Once per day if you succeed at an Intimidate check to demoralize a foe who has repudiated or ignored a pronounced judgment you've made, you may choose to cause the creature to be sickened instead of shaken. The duration of the effect remains the same.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-liquid-healing"><Link to="/trait/liquid_healing">Liquid Healing</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>Growing up in Rahadoum, you did not have access to clerics and other divine magic for healing, so you relied heavily on potions to cure your wounds. As a result, potions heal you more effectively. Whenever you consume a potion that heals any number of hit points, you heal 2 additional hit points.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-patrons-boon"><Link to="/trait/patrons_boon">Patron's Boon</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>In your youth, a Rahadoumi witch granted you a boon promoting your continued health and long life. The DCs of any Heal checks to stop bleed damage you are suffering are reduced by 4.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-pure-legion-recruit"><Link to="/trait/pure_legion_recruit">Pure Legion Recruit</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link><br/>You have spent time among the famed Pure Legion and understand some of their techniques for spotting signs of religion and the faithful. You gain a +2 trait bonus on Perception checks to see through disguises and mundane attempts to conceal religious iconography or dress. You also gain a +2 trait bonus on Sense Motive checks to see through lies about a target's religious beliefs and to understand secret messages relating to the gods.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-rahadoumi-cultist"><Link to="/trait/rahadoumi_cultist">Rahadoumi Cultist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You're a secret member of a forbidden faith in Rahadoum. You have learned to hide your beliefs and how to identify others of your faith. You gain a +5 trait bonus on Bluff checks to receive secret messages, and a +5 trait bonus on Sense Motive checks to intercept secret messages from others of your faith.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-rahadoumi-disbeliever"><Link to="/trait/rahadoumi_disbeliever">Rahadoumi Disbeliever</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Rahadoum</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>As a Rahadoumi who rejects covenants with gods, your belief is strong enough to repel divine spells. You gain a +2 trait bonus on saving throws against divine spells, but you must make a saving throw even when that magic is beneficial to you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-alchemical-prodigy"><Link to="/trait/alchemical_prodigy">Alchemical Prodigy</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link>, <Link to="/source/qadira_gateway_to_the_east">Qadira, Gateway to the East</Link><br/>Early on in your life, you showed significant promise in the sciences and alchemical arts, and received extensive tutoring from those seeking to maximize your potential. If you have the alchemy class feature, your alchemist level is considered 1 higher when calculating the duration of your extracts.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-desert-child"><Link to="/trait/desert_child">Desert Child</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia, desert</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>, <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link>, <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You were born and raised in rocky deserts, and are accustomed to high temperatures. You gain a +4 trait bonus on saving throws made to resist the effects of being in hot conditions and a +1 trait bonus on saving throws against fire effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-div-hunter"><Link to="/trait/div_hunter">Div Hunter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook</Link><br/>Divs have tormented you and your loved ones for as long as you can remember. You've improved your skills to better oppose the creatures. You gain a +2 trait bonus on Knowledge checks to identify divs (and their special powers and weaknesses) and a +1 trait bonus on weapon damage rolls against divs.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-educated-druggist"><Link to="/trait/educated_druggist">Educated Druggist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osibu, Thuvia, Tian Xia, or Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Any alchemical remedies you administer that provide an alchemical bonus have that bonus increased by 1. These remedies also restore 1 hit point to the target in addition to their usual effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-lamasaran-performer"><Link to="/trait/lamasaran_performer">Lamasaran Performer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link><br/>You are one of the famed performers of Lamasara, and your skill is known throughout Thuvia. Once per day when you start a bardic performance, you can increase the DC of the saving throw to resist your performance's effects by 1. This effect lasts until you switch performances or end your performance.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-merabian-mentorship"><Link to="/trait/merabian_mentorship">Merabian Mentorship</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia<br/><strong>Requirements:</strong> Suli</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>You were apprenticed to a renowned alchemist of Merab, and she taught you how to recognize elemental reagents by taste. Upon imbibing a potion containing a spell on your formula list of a spell level you are capable of casting, you can attempt a Spellcraft check (DC 15 + extract level). On a success, you can immediately add the spell to your formula book.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-resourceful-alchemy"><Link to="/trait/resourceful_alchemy">Resourceful Alchemy</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>Alchemy is a point of national pride in Thuvia, home of the famous <Link to="/magic-artifact/sun_orchid_elixir">sun orchid elixir</Link>. But resources are often hard to come by in the blasted desert landscape, so you have found creative ways to create many of the tools you need to survive. You gain a +2 trait bonus on Craft (alchemy) skill checks. This bonus increases to +3 when you are using Craft (alchemy) to craft an alchemical item.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-runaway-slave"><Link to="/trait/runaway_slave">Runaway Slave</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion, Thuvia, or Darklands-adjacent</p>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link><br/>Though the ghouls of Nemret Noktoria and the drow of Zirnakaynin seldom darken the surface of Golarion, both have pacts with influential slavers and warlords who periodically provide the demon worshipers with kidnapped slaves. You were once one of these unfortunate victims and were destined to become a sacrifice to a dreadful demon lord, but you managed to slip your bonds and escape back to the surface. The horrors you witnessed were beyond fathoming, and though visions of imprisoned loved ones and friends plague your dreams, you are stronger for the experience. You gain a +1 trait bonus on saves against fear effects and gain low-light vision 10 feet. If you already have low-light vision, its range extends by 10 feet.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-sun-orchid-harvester"><Link to="/trait/sun_orchid_harvester">Sun Orchid Harvester</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook</Link><br/>You were employed briefly by the blue dragon Deyrubrujuan's alchemist cabal to harvest sun orchids deep in the Thuvian desert. Though you never worked your way deeper into the cabal, you retain the knowledge gained during your employment. You gain a +1 bonus on Knowledge (nature) and Survival checks made in desert environments.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northwest_garund-thuvian-merchant"><Link to="/trait/thuvian_merchant">Thuvian Merchant</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Thuvia</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have traveled the great circular trade route around Thuvia, following the sale of the <Link to="/magic-artifact/sun_orchid_elixir">sun orchid elixir</Link> from city to city, and are used to haggling with foreigners. You gain a +1 trait bonus on Appraise, Bluff, and Sense Motive checks made for business deals and transactions.</p>
</IonLabel></IonItem></IonList>};
const _traits_northeast_garund = {title: "Regional Traits: Northeastern Garund", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-alchemical-fence"><Link to="/trait/alchemical_fence">Alchemical Fence</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>Growing up in the vast markets of Katapesh, you developed connections to a great many alchemists and poisoners all over the world. You know many of the right people in any given locale as well as how to get in touch with useful contacts. When determining whether a given potion is available in a settlement, there is a 90% chance that it is available if it is within the settlement's base value for available magic items rather than a 75% chance. Additionally, when you use Diplomacy to gather information about a topic related to alchemy or poisons (including making poisons), you gain a +3 trait bonus on the check.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-clumsy-slave"><Link to="/trait/clumsy_slave">Clumsy Slave</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Cheliax or Katapesh<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>As a former slave, you learned how to conceal your malice toward your owner behind a facade of clumsiness. The first time you attack someone with an attack that deals nonlethal damage, your target must make a Sense Motive opposed by your Bluff check minus the damage dealt to realize you actually intended to harm him; failure means he believe the injury was an accident on your part instead (though he may still want to punish you for it).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-commercial-savvy"><Link to="/trait/commercial_savvy">Commercial Savvy</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link><br/>You excel at maximizing mercantile contacts and convincing merchants to dig just a bit deeper into their pockets for you. Whenever you buy from or sell to a merchant, you treat a settlement's Base Value and Purchase Limit as 10% higher.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-duskwalker-agent"><Link to="/trait/duskwalker_agent">Duskwalker Agent</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p><strong>Sources</strong> <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link><br/>You spent a portion of your childhood working for the Duskwalkers, the guild responsible for policing and watching over all trade that takes place in Katapesh's notorious Nightstalls. You have quite a bit more spending cash than most others of your age as a result, and start with twice the normal amount of starting gold. In addition, your reputation remains strong in the Nightstalls, and any transactions you make there are always beneficial to you; items you sell net you an additional 10% profit, and items you purchase there are 10% cheaper than normal. This discount also applies to your starting gear.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-fortune-found"><Link to="/trait/fortune_found">Fortune Found</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh<br/><strong>Requirements:</strong> Vanara</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast</Link><br/>You have learned a great many tricks and techniques for bartering with humans. You gain a +1 trait bonus on Appraise and Diplomacy checks, and one of these skills (your choice) is a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-freed-slave-katapesh"><Link to="/trait/freed_slave_katapesh">Freed Slave (Katapesh)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p><strong>Sources</strong> <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link><br/>You spent a significant portion of your childhood as a slave, but were freed from slavery several years ago by a benevolent master who purchased you from an auction after your previous master's death. Yet while the memories of your difficult childhood still haunt you, the hard life did toughen you. You gain a +1 trait bonus on Fortitude saves.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-merchants-child"><Link to="/trait/merchants_child">Merchant's Child</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link><br/>One of your close relatives was a gifted merchant in the bustling bazaars of Katapesh, and taught you early in life how to see the innate value in any object. You gain a +1 trait bonus on Appraise checks, and Appraise is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-nightstall-urchin"><Link to="/trait/nightstall_urchin">Nightstall Urchin</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p><strong>Sources</strong> <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link><br/>You grew up an orphan on the streets of Katapesh, and spent many years of childhood in the Nightstalls, Katapesh's most infamous market. The strange and often horrific sights you saw there forced you to grow up fast-there's little that can shock or unsettle you. You gain a +2 trait bonus on saves against fear effects, and when you do make a successful save against a fear effect, the resulting rush of bravado grants you a +1 trait bonus on attack rolls and all skill checks for the next minute.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-nightstalls-escapee"><Link to="/trait/nightstalls_escapee">Nightstalls Escapee</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh<br/><strong>Requirements:</strong> Ifrit</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>The slavers of Katapesh were determined to sell you as living property, but you had other plans. You know not whether your slavers hunt you still, but you are careful about whom you trust and you always sleep with one eye open. You need to sleep only 4 hours to get <Link to="/rule/healing">a full night's rest</Link> (restoring 1 hit point per character level). You do not receive extra benefits for sleeping additional hours, and you must still rest for 24 hours to receive the benefits of complete bed rest.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-pesh-addict"><Link to="/trait/pesh_addict">Pesh Addict</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link>, <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link><br/>You spent several years addicted to pesh, a habit that you may or may not have kicked. You start with only half of the normal starting cash, but your knowledge of the pesh lifestyle grants you a +1 trait bonus on Bluff, Knowledge (local), and Sense Motive checks. One of these skills (your choice) is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-pesh-dealer"><Link to="/trait/pesh_dealer">Pesh Dealer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p><strong>Sources</strong> <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link><br/>You worked for a pesh dealer, either by selling the drug on the street or helping to organize shipments to other regions, which involved a certain amount of smuggling. You gain a +1 trait bonus on Sleight of Hand checks, and Sleight of Hand is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-savanna-child"><Link to="/trait/savanna_child">Savanna Child</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh, plains</p>
<p><strong>Sources</strong> <Link to="/source/ultimate_campaign">Ultimate Campaign</Link>, <Link to="/source/advanced_players_guide">Advanced Player's Guide</Link>, <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link><br/>You were born and raised in central Katapesh, among the rolling savannahs that dominate the nation's interior. You spent many of your youth exploring these vast reaches, and know much of the savannah's secrets. Pick one of the following skills: Handle Animal, Knowledge (nature), or Ride. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-uwaga-highlander"><Link to="/trait/uwaga_highlander">Uwaga Highlander</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Katapesh</p>
<p><strong>Sources</strong> <Link to="/source/legacy_of_fire_players_guide">Legacy of Fire Player's Guide</Link><br/>You were born and raised in western Katapesh, in the rugged badlands and hills of the Uwaga Highlands. Even if you were born in a city like Solku, you often had to travel the dangerous trails with your family. Predators, gnolls, and worse haunt the Uwaga Highlands, and you've become something of an expert at evading them. You gain a +1 trait bonus on Stealth checks. This trait bonus increases to +2 in hilly or rocky areas.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-abolitionist-hunter"><Link to="/trait/abolitionist_hunter">Abolitionist Hunter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Okeno</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You hunt those who hunt slavers, whether as one of Captain Bhey's special task forces, or independently. You gain a +1 trait bonus on attack rolls when fighting abolitionists or those you have good reason to believe targeted you because of your slaver activities.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-cruel-master"><Link to="/trait/cruel_master">Cruel Master</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Okeno</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You're a master of dominating slaves through body language and inflection, and this ability carries over into other lines of work as well. You gain a +1 trait bonus on Intimidate checks, and it becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-slave-taker"><Link to="/trait/slave_taker">Slave Taker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Okeno</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You specialize in disabling foes without wounding them, preserving their value as slaves. Whenever you deal nonlethal damage in combat, that damage increases by +1.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-whip-specialist"><Link to="/trait/whip_specialist">Whip Specialist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Okeno</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>Your time spent lashing slaves has taught you how to get the most out of a whip. You deal +1 point of damage on all attacks made with a whip.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-antiquities-smuggler"><Link to="/trait/antiquities_smuggler">Antiquities Smuggler</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have moved contraband relics from Osirion's elder days for years, and have learned some tricks. Choose one of the following skills: Appraise, Bluff, or Sleight of Hand. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-cheap-to-feed"><Link to="/trait/cheap_to_feed">Cheap to Feed</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion or Varisia<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>Life in a big city taught the consequences of pride. Now you have no qualms about pointing out how little of a burden your upkeep would prove to potential employers, captors, innkeepers, or anyone else able to provide you with the necessities of life. You gain a +3 trait bonus on Bluff checks made in order to gain food, water, or shelter.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-child-of-mumia"><Link to="/trait/child_of_mumia">Child of Mumia</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link><br/>During your childhood, you knew someone who was addicted to <Link to="/drug/mumia">mumia</Link>, a drug made from the flesh of the dead, whether that was a drug-addled parent, an unsavory employer, or a libertine childhood friend. Although you did not indulge in the ghoulish narcotic yourself, your exposure to it grants you a +1 trait bonus on saving throws against curses and diseases, including magical diseases.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-child-of-wati"><Link to="/trait/child_of_wati">Child of Wati</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link><br/>You were raised near the infamous necropolis of Wati, and even managed to sneak into these hallowed grounds on occasion. Entering the clergy of the Voices of the Spire in Wati was a natural choice as you grew older, and your past experiences made you a particularly well-informed disciple of the church. Your effective cleric level is 1 higher for the purposes of channeling positive energy to damage undead. Your effective cleric level cannot exceed your character level.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-curse-queller"><Link to="/trait/curse_queller">Curse Queller</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Whenever a caster level check is required to treat an affliction with magic (such as when casting <Link to="/spell/remove_curse">remove curse</Link> on a cursed creature or object), you gain a +2 trait bonus on your caster level check. Additionally, you gain a +1 trait bonus on your saving throws against curses.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-elemental-endowment"><Link to="/trait/elemental_endowment">Elemental Endowment</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance</Link><br/>You see the interactions between elementals as the epitome of balance; you've studied the traditional elemental bindings of Ancient Osirion and can draw upon their power. As an immediate action, once per day when you cast a spell with the air, earth, fire, or water descriptor, you can gain a number of temporary hit points equal to the spell's level. This effect lasts for 1 minute.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-elemental-ties"><Link to="/trait/elemental_ties">Elemental Ties</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook</Link><br/>Interactions with elementals are commonplace for you. You gain a +1 trait bonus on Diplomacy checks when dealing with creatures of the elemental type, and you begin play knowing one of the following languages as an additional bonus language: Aquan, Auran, Ignan, or Terran.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-empathic-diplomat"><Link to="/trait/empathic_diplomat">Empathic Diplomat</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Qadira or Osirion</p>
<p><strong>Sources</strong> <Link to="/source/qadira_jewel_of_the_east">Qadira, Jewel of the East</Link><br/>You have long followed the path of common sense and empathic insight when using diplomacy. You modify your Diplomacy checks using your Wisdom modifier, not your Charisma modifier.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-legalistic-liberation"><Link to="/trait/legalistic_liberation">Legalistic Liberation</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Molthune or Osirion<br/><strong>Requirements:</strong> Halfling</p>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion</Link><br/>You followed - or some might say exploited - the rules and earned your freedom by finding the loopholes within your homeland's labyrinthine codes regulating slavery and indentured servitude. You gain a +1 bonus on all Knowledge checks to find a legitimate way to avoid, negate, or escape an existing obligation.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-numerologist"><Link to="/trait/numerologist">Numerologist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands</Link><br/>Having studied the sciences and other formal academics in your formative years, you swiftly became interested in the esoteric numerological practices of the ancient Osirian mathematicians, and know how to apply this science to dungeons. Once per day, you can attempt a Perception check while studying a trap (a standard action). The DC of this check is equal to the Disable Device DC of the trap - 5. If you succeed, you identify the DC necessary to disable the trap, as well as the DC of the Reflex save (if any) to avoid its effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-offspring-of-the-ascension"><Link to="/trait/offspring_of_the_ascension">Offspring of the Ascension</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_stars">People of the Stars</Link><br/>You are descended from one of Ancient Osirion's pharaohs, and a sliver of her otherworldly power has been passed onto you. You gain a +1 trait bonus on Will saves against fear effects. Any time you become confused, reduce the duration of the effect by a number of rounds equal to your Wisdom modifier (to a minimum of 1 round of confusion).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-osirionologist"><Link to="/trait/osirionologist">Osirionologist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have studied the history of ancient Osirion, and may have even ventured inside one of the great pyramids. You gain a +1 trait bonus on Knowledge (engineering) and Knowledge (history) checks, and one of them is always a class skill for you. In addition, you may choose Ancient Osiriani as one of your bonus languages.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-runaway-slave"><Link to="/trait/runaway_slave">Runaway Slave</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion, Thuvia, or Darklands-adjacent</p>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link><br/>Though the ghouls of Nemret Noktoria and the drow of Zirnakaynin seldom darken the surface of Golarion, both have pacts with influential slavers and warlords who periodically provide the demon worshipers with kidnapped slaves. You were once one of these unfortunate victims and were destined to become a sacrifice to a dreadful demon lord, but you managed to slip your bonds and escape back to the surface. The horrors you witnessed were beyond fathoming, and though visions of imprisoned loved ones and friends plague your dreams, you are stronger for the experience. You gain a +1 trait bonus on saves against fear effects and gain low-light vision 10 feet. If you already have low-light vision, its range extends by 10 feet.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_northeast_garund-snake-handler"><Link to="/trait/snake_handler">Snake Handler</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osirion<br/><strong>Religion:</strong> <Link to="/faith/apep">Apep</Link> or <Link to="/faith/wadjet">Wadjet</Link></p>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link><br/>You have spent time as a member of a cult of either Apep or Wadjet, the serpent gods of Osirion. Membership involved the handling of dangerous snakes during rituals, and you have learned how to keep yourself and others safe around them. You gain a +2 bonus on Fortitude saves against poison. Handle Animal is always a class skill for you.</p>
</IonLabel></IonItem></IonList>};
const _traits_lung_wa = {title: "Regional Traits: Former Lung Wa Empire", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-exhibition-fighter"><Link to="/trait/exhibition_fighter">Exhibition Fighter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lung Wa</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 23</Link><br/>You fight at your best in martial arts tournaments, such as those once popular in Lung Wa and still common in Quain. While others may attempt to cheat or chafe against the constraints placed upon them, you thrive under such limitations. You gain a +1 bonus on attack and damage rolls when fighting as part of a tournament or other structured setting with rules and restrictions, so long as you do not break these rules.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-godless-resolve"><Link to="/trait/godless_resolve">Godless Resolve</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bachuan, Rahadoum or Touvette</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Some brilliant and earnest speech or other performance inspired you to take charge of your own health rather than begging indifferent or outlawed deities for deliverance. Heal is a class skill for you, and you gain a +2 trait bonus on Heal checks to stabilize dying creatures and stop bleeding.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-szaezan-crags-miner"><Link to="/trait/szaezan_crags_miner">Szaezan Crags Miner</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bachuan</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were a miner of the now-scarce ores of the Szaezan Crags, and have become adept at identifying minerals and gems. You gain a +1 trait bonus on Appraise checks, and Appraise becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-tiger-brigadier"><Link to="/trait/tiger_brigadier">Tiger Brigadier</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bachuan</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>As a member of the Tiger Brigade, you are ready to guide the people of Bachuan and other nations. You gain a +2 trait bonus on Intimidate checks made against anyone whose age is one or more aging steps above yours, and Intimidate becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-acupuncturist"><Link to="/trait/acupuncturist">Acupuncturist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Chu Ye</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You have studied the ancient art of acupuncture, and use it to pursue enlightenment and healing. You gain a +2 trait bonus on all Fortitude saves made against poison effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-mizu-ki-hikari-rebel"><Link to="/trait/mizu_ki_hikari_rebel">Mizu Ki Hikari Rebel</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Chu Ye</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You have trained in martial arts under the banner of Mizu Ki Hikari rebels. You gain a +1 trait bonus on damage rolls made with unarmed attacks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-cosmopolitan"><Link to="/trait/cosmopolitan">Cosmopolitan</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Goka</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link>, <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>Your exposure to the many peoples intersecting in Goka and the tongues spoken there has given you a particular facility for speech. You gain a +1 trait bonus on Linguistics checks, and Linguistics becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-undermarket-smuggler"><Link to="/trait/undermarket_smuggler">Undermarket Smuggler</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Goka</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You worked in Goka's Undermarket for a time, and have learned how to dodge the city's tax collectors and the port inspectors. You gain a +1 trait bonus on Bluff and Sleight of Hand checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-indentured-blacksmith"><Link to="/trait/indentured_blacksmith">Indentured Blacksmith</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kaoling</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>As a former slave of the hobgoblins, you were forced to make many of the weapons and shields that your captors used in war. Choose either Craft (armor) or Craft (weapons). You gain a +1 trait bonus on the chosen skill, and it becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-privileged-slave"><Link to="/trait/privileged_slave">Privileged Slave</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Kaoling</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were enslaved by the hobgoblins of Kaoling, and obeyed your masters dutifully, turning your back on comrades in order to find favor with your slavers-all the while plotting your escape. You gain a +1 trait bonus on Bluff checks, and Bluff becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-heart-of-clay"><Link to="/trait/heart_of_clay">Heart of Clay</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lingshen</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You believe you are destined for an afterlife of service as part of King Huang's terra-cotta army, so you do not fear death as others do. You gain a +1 trait bonus on Fortitude saves.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-lingshens-finest"><Link to="/trait/lingshens_finest">Lingshen's Finest</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lingshen</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You are an elite soldier in one of Lingshen's numerous armies, and your discipline has made you a truly deadly foe. You gain a +1 trait bonus on all rolls to confirm critical hits.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-sky-spirit-worshipper"><Link to="/trait/sky_spirit_worshipper">Sky Spirit Worshipper</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mutabi-qi</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>As the child of a Mutabi-qi shaman, you have seen the sky spirits that roam above and know that the world is rife with unexplainable and terrifying mysteries. You gain a +2 trait bonus on saves against fear effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-chosen-child"><Link to="/trait/chosen_child">Chosen Child</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Po Li</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>The oracles of Po Li smiled upon you when your parents claimed you were of divine right, and you were raised with privileges few Po Lians can fathom. Your starting money increases by 900 gp.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-passionate-believer"><Link to="/trait/passionate_believer">Passionate Believer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Po Li</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>Your faith was stifled while you lived in the religiously oppressive slums of Changdo, and the persecutions against you only spurred your own beliefs and made your convictions stronger. You gain a +1 trait bonus on saving throws against divine spells.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-quain-martial-artist"><Link to="/trait/quain_martial_artist">Quain Martial Artist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Quain</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>Having grown up in Quain, you were taught under various schools of martial arts, and have used all you have learned to hone your fighting prowess. You gain a +1 trait bonus on damage rolls when using unarmed strikes.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-silvertongued-eunuch"><Link to="/trait/silvertongued_eunuch">Silvertongued Eunuch</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Quain</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were brought up as part of Quain's strictly eunuch bureaucracy, trading your sexual potency for education and tact. You gain a +1 trait bonus on Knowledge (nobility) and Diplomacy checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-aberration-hunter"><Link to="/trait/aberration_hunter">Aberration Hunter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Shenmen</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You refuse to give in to the monsters that feast on your people, and hunt them instead. You gain a +1 trait bonus on attacks of opportunity against aberrations.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-shenmen-prospector"><Link to="/trait/shenmen_prospector">Shenmen Prospector</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Shenmen</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were a talented laborer in the silver mines of Shenmen, and have seen many wonders in the haunted caverns beneath the surface of the cursed nation. You gain a +1 trait bonus on Appraise and Knowledge (dungeoneering) checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-freedom-fighter-shokuro"><Link to="/trait/freedom_fighter_shokuro">Freedom Fighter (Shokuro)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Shokuro</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You come from a family of farmers, but are determined to fight for your rights. You gain a +1 trait bonus on attacks made with improvised weapons. If you do not possess the <Link to="/feat/catch_off_guard">Catch Off-Guard</Link> or <Link to="/feat/throw_anything">Throw Anything</Link> feats, you still take penalties on these attack rolls as normal.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-rebel-leader"><Link to="/trait/rebel_leader">Rebel Leader</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Shokuro</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>A close relative was an important player in the rebellions that led to the independence of Shokuro, and passed on her passion to you. If you take the <Link to="/feat/leadership">Leadership</Link> feat, you receive a +1 trait bonus to your Leadership score.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-rice-runner"><Link to="/trait/rice_runner">Rice Runner</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Wanshou</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You grew up as a slave in Wanshou, harvesting rice for your kraken despot, and you know how to move agilely across sodden and unsteady ground. You gain a +1 trait bonus on Acrobatics checks, and Acrobatics becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-swamp-rebel"><Link to="/trait/swamp_rebel">Swamp Rebel</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Wanshou</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You grew up hiding in the swamps from the monstrous overlords who enslaved you and your people. You gain a +2 trait bonus on Stealth checks in swampy terrain, and Stealth becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-clan-artisan"><Link to="/trait/clan_artisan">Clan Artisan</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Xa Hoi</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were raised in one of the numerous clans of Xa Hoi, and learned a valuable trade in your early years. Pick one Craft skill. You gain a +2 trait bonus on checks with that skill, and it becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_lung_wa-xa-hoi-soldier"><Link to="/trait/xa_hoi_soldier">Xa Hoi Soldier</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Xa Hoi</p>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer</Link><br/>You were a soldier in one of Xa Hoi's extensive armies, trained under the oversight of one of Pham Duc Quan's draconic brethren. You gain a +1 trait bonus on Reflex saves.</p>
</IonLabel></IonItem></IonList>};
const _traits_mana_wastes = {title: "Regional Traits: Mana Wastes", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-alkenstar-defender"><Link to="/trait/alkenstar_defender">Alkenstar Defender</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mana Wastes</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have lived in Alkenstar and served in its militia. You know just where to aim to do the most damage. You gain a +1 trait bonus on all rolls to confirm critical hits with ranged weapons.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-alkenstar-engineer"><Link to="/trait/alkenstar_engineer">Alkenstar Engineer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mana Wastes</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes</Link><br/>Your extensive experience with firearms allows you to get the most out of those unique weapons. When you're wielding a broken early firearm, the amount your misfire value increases by is reduced by 1.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-mana-wastes-medic"><Link to="/trait/mana_wastes_medic">Mana Wastes Medic</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mana Wastes</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>After witnessing a terrible disaster result from an attempt at magical healing in the Mana Wastes, you are careful and methodical when crafting your own healing tinctures. The amount of hit points restored by your Heal checks to treat deadly wounds and your extracts of the healing subschool is increased by 1.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-mana-wastes-survivalist"><Link to="/trait/mana_wastes_survivalist">Mana Wastes Survivalist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mana Wastes</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You grew up in the blasted badlands of the Mana Wastes, or have spent a lot of time there, and the harsh land has toughened your body. You gain a +1 trait bonus on Fortitude saves.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-mechanical-expertise"><Link to="/trait/mechanical_expertise">Mechanical Expertise</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Alkenstar</p>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link><br/>Growing up bordering the Mana Wastes and living within the Grand Duchy of Alkenstar has made you familiar with tools and practical objects. You rely on mechanics to solve problems and are familiar with basic engineering concepts. Select one of the following skills: Craft (any), Disable Device, or Knowledge (engineering). You gain a +1 trait bonus on checks with that skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-enemy-of-the-undead"><Link to="/trait/enemy_of_the_undead">Enemy of the Undead</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Geb</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>Your disgust at the way the undead aristocracy of Geb treats the living has inspired hatred in you. You gain a +2 trait bonus on saving throws against any spells or spell-like abilities from an undead creature.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-forbidden-knowledge"><Link to="/trait/forbidden_knowledge">Forbidden Knowledge</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Geb</p>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link><br/>As a child, you somehow got your hands on a lurid, forbidden text written by a now-forgotten Blood Lord of ages past. You studied the details within intently, learning much about extraplanar undead from beyond this reality, and you developed a strange, almost macabre way of thinking because of this book's influence. Anytime you would roll a Knowledge (planes) check, you may roll a Knowledge (history) or Knowledge (religion) check instead.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-friend-of-the-dead"><Link to="/trait/friend_of_the_dead">Friend of the Dead</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Geb</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>Your close association with the intelligent undead of Geb has imparted some of their otherworldly essence to you, and this essence helps you in your dealings with the undead. You gain a +2 trait bonus on Diplomacy checks against sentient undead.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-necrotoxin-resistance"><Link to="/trait/necrotoxin_resistance">Necrotoxin Resistance</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Geb</p>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>As a resident of the undead lands of Geb, you know well that the walking dead often carry deadly poisons and diseases within them. You gain a +3 trait bonus on saving throws against disease and poison abilities and effects inflicted by creatures of the undead type (such as ghoul fever or a vargouille's poison).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-obsequious-morsel"><Link to="/trait/obsequious_morsel">Obsequious Morsel</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Geb</p>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link><br/>Survival in Geb requires convincing your betters that you would be of more service to them if they let you live another day than if they turn you into an unliving thrall, and you have mastered the art of buying time against undead attacks. Once per day as a swift action, you can use <Link to="/spell/sanctuary">sanctuary</Link> as a spell-like ability (caster level = your highest caster level, or 1st if you have no caster level), with a DC equal to 10 + 1/2 your caster level (minimum 0) + your Charisma modifier. Only undead must save to attack you (other creature types are not affected). The effect ends as soon as you attack a creature, as normal.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-exiled-scholar"><Link to="/trait/exiled_scholar">Exiled Scholar</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nex</p>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook</Link><br/>Since you were young, you've always been interested in the process of lichdom and what drives people to desire such a fate. Nexian officials marked you as a traitor and exiled you when they discovered your morbid fascination with the consummate undead, but you still benefit from your forbidden studies. You gain a +1 trait bonus on Knowledge (arcana) and (religion) checks. In addition, choose one Knowledge skill; you can attempt untrained checks with this skill as long as the DC is lower than 15.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-nexian-corpse-hunter"><Link to="/trait/nexian_corpse_hunter">Nexian Corpse Hunter</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nex</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>After years spent fighting the undead legions of Geb, you have developed a knack for killing undead creatures with magic. You gain a +1 bonus on damage rolls from your spells against undead.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-oenopion-alchemist"><Link to="/trait/oenopion_alchemist">Oenopion Alchemist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nex</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You studied with the alchemists of Oenopion, perfecting your craft in the homunculus factories, golemworks, and ooze colony. You gain a +1 trait bonus on Craft (alchemy) checks.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mana_wastes-quantium-university-graduate"><Link to="/trait/quantium_university_graduate">Quantium University Graduate</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Nex</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You graduated from one of Quantium's justly famous arcane academies, and the rigorous program of study has honed your mind. You gain a +2 trait bonus on <Link to="/rule/concentration">concentration</Link> checks when casting arcane spells.</p>
</IonLabel></IonItem></IonList>};
const _traits_mwangi_expanse = {title: "Regional Traits: Mwangi Expanse", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mwangi_expanse-artifact-hunter-isp"><Link to="/trait/artifact_hunter_isp">Artifact Hunter (ISP)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You know the legends of the Mwangi Expanse and the places where great treasures were rumored to have fallen. You gain a +1 trait bonus on Knowledge (geography) and Knowledge (history) checks, and one of them is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mwangi_expanse-charau-ka-slayer"><Link to="/trait/charau_ka_slayer">Charau-Ka Slayer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p><strong>Sources</strong> <Link to="/source/demon_hunters_handbook">Demon Hunter's Handbook</Link><br/>As a native of the Mwangi Jungle, you've had frequent encounters with the charau-ka and learned how to fight against these coldly calculating demon worshipers. You gain a +1 trait bonus to AC against attacks made with thrown weapons.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mwangi_expanse-jungle-native"><Link to="/trait/jungle_native">Jungle Native</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse<br/><strong>Requirements:</strong> Grippli</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast</Link><br/>Your people have called the jungles home for generations, and they are extremely proficient in moving about in that terrain. You gain a +1 trait bonus on saving throws against diseases and poisons, a +1 trait bonus on initiative checks attempted in jungle terrain, and Survival is a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mwangi_expanse-jungle-walker"><Link to="/trait/jungle_walker">Jungle Walker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have learned how to navigate the darkest jungles of the Mwangi Expanse, and how to avoid the most dangerous hazards of the land. You gain a +2 trait bonus on Survival checks in jungle terrain.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mwangi_expanse-left-behind"><Link to="/trait/left_behind">Left Behind</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse or Varisia<br/><strong>Requirements:</strong> Elf</p>
<p><strong>Sources</strong> <Link to="/source/elves_of_golarion">Elves of Golarion</Link><br/>Having been born to those who chose to remain on Golarion during the Age of Darkness in the Mwangi Expanse, you understand the people of this world better than most elves. You gain a +1 trait bonus on Diplomacy checks when interacting with Forlorn elves and non-elf races.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mwangi_expanse-mwangi-herbal-tradition"><Link to="/trait/mwangi_herbal_tradition">Mwangi Herbal Tradition</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>You are trained in a Mwangi tradition of herbalism dating back to the Age of Darkness and therefore have great insight into how to use the natural ingredients at your disposal to nurse an ailing body. You gain a +4 trait bonus on Heal checks when providing long-term care, and Heal is a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mwangi_expanse-mwangi-linguist"><Link to="/trait/mwangi_linguist">Mwangi Linguist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe</Link><br/>The Mwangi Expanse is a land of dozens of languages, and you grew up speaking most of them. You gain Polyglot as a bonus language. In addition, you gain a +1 trait bonus on Linguistics checks when trying to communicate with someone who does not share a common language with you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mwangi_expanse-scion-of-the-shory"><Link to="/trait/scion_of_the_shory">Scion of the Shory</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>The blood of a Shory aeromancer flows through your veins. You gain a +2 bonus on <Link to="/rule/concentration">concentration</Link> checks when casting flight spells such as <Link to="/spell/levitate">levitate</Link>, <Link to="/spell/fly">fly</Link>, or <Link to="/spell/overland_flight">overland flight</Link>. Once per day, you can use <Link to="/spell/message">message</Link> as a spell-like ability.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mwangi_expanse-wild-wanderer"><Link to="/trait/wild_wanderer">Wild Wanderer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mwangi Expanse</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>You're a child of the wild, living on your own without need of others. Each time you attempt a Survival check to get along in the wild or resist severe weather, you can choose to gain a +4 trait bonus on that check. If you do so, you can't use that check to provide assistance to others, even if your result exceeds the DC.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_mwangi_expanse-educated-druggist"><Link to="/trait/educated_druggist">Educated Druggist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Osibu, Thuvia, Tian Xia, or Ustalav</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Any alchemical remedies you administer that provide an alchemical bonus have that bonus increased by 1. These remedies also restore 1 hit point to the target in addition to their usual effects.</p>
</IonLabel></IonItem></IonList>};
const _traits_river_kingdoms = {title: "Regional Traits: River Kingdoms", jsx: <IonList lines="full"><MainLink to="/main/traits_regional" className="reversed" info="Back to Regional Traits" /><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-bandit"><Link to="/trait/bandit">Bandit</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>Since you were young, you've been a member of one River Kingdoms bandit gang or another. Choose one of the following skills: Escape Artist, Intimidate, or Stealth. You gain a +1 trait bonus on that skill, and it is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-expert-swimmer"><Link to="/trait/expert_swimmer">Expert Swimmer</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>Most pirates on the ocean view falling overboard as a death sentence, but in the River Kingdoms, it's often a key part of the strategy. You gain a +1 trait bonus on Swim checks, and it becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-free-agent"><Link to="/trait/free_agent">Free Agent</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You embody the independent spirit of the River Kingdoms and do best when sailing under your own flag, in every sense. You gain a +2 trait bonus on Will saves to avoid charm and compulsion effects.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-greenskin-stalker"><Link to="/trait/greenskin_stalker">Greenskin Stalker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Isger, River Kingdoms, or Varisia</p>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins</Link><br/>You're a member of the Greenskin Stalkers. Due to your affiliation with this brotherhood of goblin slayers, you've learned to think and act like a goblin, as disturbing as that sounds. You receive a +1 trait bonus on Bluff, Knowledge, Perception, Sense Motive, and Survival checks against or concerning goblinoids. You can also attempt Knowledge checks concerning goblinoids untrained.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-outsea-native"><Link to="/trait/outsea_native">Outsea Native</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms<br/><strong>Requirements:</strong> Undine</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_elements">Blood of the Elements</Link><br/>Raised amid or near the transitive aquatic kingdom known as Outsea, your predilection for watery environs has been strong since birth and you know the types of creatures who call the ocean home. You gain a +2 trait bonus on Knowledge checks to identify aquatic monsters. Anytime you are looking through water and would take a penalty on vision-based Perception checks due to murkiness or other natural circumstances, reduce the penalty by 2.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-poisoned-blade-resistance"><Link to="/trait/poisoned_blade_resistance">Poisoned Blade Resistance</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>In the River Kingdoms' Daggermark, odds are good that any given blade is coated in some kind of poison, and people there are used to both poisoning and being poisoned. You gain a +2 trait bonus on Fortitude saving throws against injury poisons. Additionally, you are immune to one specific nonmagical injury poison. You must choose this poison when you choose this trait and cannot change it.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-river-navigator"><Link to="/trait/river_navigator">River Navigator</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>You grew up in the River Kingdoms and are familiar with the many winding streams that cross the land. You gain a +1 trait bonus on Survival checks or Profession (sailor) checks dealing with lakes, rivers, and their immediate surroundings, and one of these skills becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-river-sniper"><Link to="/trait/river_sniper">River Sniper</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p><strong>Sources</strong> <Link to="/source/pirates_of_the_inner_sea">Pirates of the Inner Sea</Link><br/>Unlike seagoing pirates, you're used to fighting most of your ship-to-ship battles at close range, and understand the value of a well-placed arrow. When on the deck of a waterborne vessel, you gain a +1 trait bonus on attacks with ranged weapons.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-riverfolk"><Link to="/trait/riverfolk">Riverfolk</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You've grown up on the tributaries of the Sellen River system, and are as comfortable on boats as on land. You gain a +2 trait bonus on Profession (sailor) checks and any skill checks involving rope use.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-swamp-skulker"><Link to="/trait/swamp_skulker">Swamp Skulker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven</Link><br/>Terrible things prowl the moors of your homeland, and you are all too familiar with hiding or fleeing from them. You gain a +1 trait bonus on Stealth checks when you are in bog, marsh, or swamp terrain, and you treat shallow bogs and swamp undergrowth as normal terrain for the purposes of movement.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-water-brave"><Link to="/trait/water_brave">Water Brave</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> River Kingdoms</p>
<p><strong>Sources</strong> <Link to="/source/orcs_of_golarion">Orcs of Golarion</Link><br/>Travel through the dangerous waters of the River Kingdoms has given your tribe special skills in relation to them. You receive a +1 trait bonus on Swim checks, and it becomes a class skill.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-the-vessel-between"><Link to="/trait/the_vessel_between">The Vessel Between</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Daggermark</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>The assassin ushers her victims from the kingdoms of the living to the kingdom of the dead. You gain a +1 trait bonus on attack rolls that would deal sneak attack damage on a hit.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-wary-potr"><Link to="/trait/wary_potr">Wary (PotR)</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Daggermark</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>You survived an assassination attempt once. You gain a +1 trait bonus on opposed Perception and Sense Motive checks. One of these skills is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-crusader-road-acolyte"><Link to="/trait/crusader_road_acolyte">Crusader Road Acolyte</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Echo Wood or Thornkeep</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>You trained with the <Link to="/rule/hellknights">Hellknights</Link> at Fort Inevitable or the paladins of Iomedae at Fort Riverwatch. If you trained with the Hellknights, you gain a +1 trait bonus on saving throws against chaotic spells and the spell-like abilities of chaotic outsiders. If you trained with the Iomedaean Paladins, you gain this bonus against evil spells and evil outsiders instead.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-noble-in-exile"><Link to="/trait/noble_in_exile">Noble-in-Exile</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Gralton</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>Though forced to live in the River Kingdoms, you never forget you're a Galtan noble. You gain a +1 trait bonus on Diplomacy checks while interacting with aristocrats and nobles, and a +1 trait bonus on Intimidate checks while interacting with commoners.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-black-eagle-recruit"><Link to="/trait/black_eagle_recruit">Black Eagle Recruit</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lambreth</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>You were recruited to serve as one of Lord Arnefax's feared Black Eagles for a time, but you have since left that life. You gain a +1 trait bonus on saves against fear effects; this bonus increases to +3 if an evil outsider caused the effect.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-blackthorn-rancher"><Link to="/trait/blackthorn_rancher">Blackthorn Rancher</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Lambreth</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>Domestic animals from Lambreth are known for their resiliency. You gain a +1 trait bonus on Handle Animal checks and Handle Animal is a class skill for you. Your animal companion or bonded mount gains a permanent +3 trait bonus to its maximum hit point total.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-brevoy-bandit"><Link to="/trait/brevoy_bandit">Brevoy Bandit</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mivon</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>You fled the persecution of Brevoy authorities and wound up in Mivon. Whether or not you are guilty of your alleged crimes, you seek to build a new life amid new neighbors. Choose one Profession skill and one ability score other than Wisdom. You add that ability score's modifier in addition to your Wisdom modifier on checks with the chosen Profession skill.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-mivoni-duelist"><Link to="/trait/mivoni_duelist">Mivoni Duelist</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Mivon</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>Your training in Aldori sword fighting included several bouts in the Sevier, which has taught you how to inflict further punishment in one-on-one fights. You gain a +1 trait bonus on damage rolls when you are the only one threatening your opponent.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-pitaxian-improvisation"><Link to="/trait/pitaxian_improvisation">Pitaxian Improvisation</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Pitax</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>Your quick hands can salvage even the most botched performance. Once per day after you attempt a Perform check and before the results of the roll are revealed by the GM, you can attempt a Bluff check and use the result of that check in place of your Perform check. You must use the result of that Bluff check, even if it is lower.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-acolyte-of-razmir"><Link to="/trait/acolyte_of_razmir">Acolyte of Razmir</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Razmiran</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You are an adherent of the Razmiri faith, or once were and have since renounced it. You gain a +1 trait bonus on Knowledge (local) and Knowledge (religion) checks, and one of these skills is always a class skill for you. This bonus increases to +2 when dealing with specifics of the Razmiri faith.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-divine-deceiver"><Link to="/trait/divine_deceiver">Divine Deceiver</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Razmiran</p>
<p><strong>Sources</strong> <Link to="/source/champions_of_corruption">Champions of Corruption</Link><br/>You are trained in the methods of Razmir's priesthood, and can use your arcana to fuel minor healing powers. Once per day as a full-round action, you can sacrifice a prepared arcane spell or spell slot to manifest healing magic. This acts as cure light wounds, except you heal 1d6 points of damage per level of the spell or spell slot sacrificed (maximum 5d6) and the hit points healed are temporary (lasting 1 hour).</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-palm-potion"><Link to="/trait/palm_potion">Palm Potion</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Razmiran</p>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons</Link><br/>Priests of Razmiran often make subtle use of potions to hide the fact that they do not receive spells from their deity, and they have become quite adept at imbibing potions surreptitiously. You have mastered these techniques; whenever you consume a potion, you can attempt a Sleight of Hand check with a +2 trait bonus opposed by onlookers' Perception checks to hide the fact that you are drinking a potion (as if you were using Sleight of Hand to hide an object). The observer's success doesn't prevent you from drinking the potion, just from doing so unnoticed. This does not hide any visible effects that the potion might have on you, only the physical act of drinking the potion.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-soldier-of-the-faith"><Link to="/trait/soldier_of_the_faith">Soldier of the Faith</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Razmiran</p>
<p><strong>Sources</strong> <Link to="/source/inner_sea_primer">Inner Sea Primer</Link><br/>You have served Razmir as a faithful enforcer, or upon one of the "faith barges" plying the waters of Lake Encarthan, and have learned the enforcement techniques of Razmiran. You gain a +1 trait bonus on Intimidate checks, and Intimidate is always a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-fey-wise"><Link to="/trait/fey_wise">Fey-Wise</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sevenarches</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>You grew up around fey and are accustomed to their tricks. You gain a +1 trait bonus on saving throws against the spell-like and supernatural abilities of fey and a +1 trait bonus on Sense Motive checks against fey.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-sevenarches-seeker"><Link to="/trait/sevenarches_seeker">Sevenarches Seeker</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Sevenarches</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>You've long heard rumors about the mysterious archways of Sevenarches and have spent much of your life trying to unravel the mysteries behind the portals. You gain a +1 trait bonus on Knowledge (history) checks and Perception checks to notice secret doors, and Knowledge (history) becomes a class skill for you.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-godless-resolve"><Link to="/trait/godless_resolve">Godless Resolve</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Bachuan, Rahadoum or Touvette</p>
<p><strong>Sources</strong> <Link to="/source/healers_handbook">Healer's Handbook</Link><br/>Some brilliant and earnest speech or other performance inspired you to take charge of your own health rather than begging indifferent or outlawed deities for deliverance. Heal is a class skill for you, and you gain a +2 trait bonus on Heal checks to stabilize dying creatures and stop bleeding.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-valknar-alumnus"><Link to="/trait/valknar_alumnus">Valknar Alumnus</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Tymon</p>
<p><strong>Sources</strong> <Link to="/source/people_of_the_river">People of the River</Link><br/>You trained at the exclusive Valknar Gladiatorial College. Select one combat maneuver when you take this trait. You gain a +1 trait bonus on performance combat checks and a +1 trait bonus on combat maneuver checks to perform the selected maneuver.</p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><h2 id="main-traits_river_kingdoms-unstuck"><Link to="/trait/unstuck">Unstuck</Link></h2>
<p><strong>Type:</strong> Regional<br/><strong>Region:</strong> Uringen</p>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World</Link><br/>Spending time in the "unstuck" part of Uringen has made you more adept at using warps in time and space. Increase your caster level by 2 when casting spells with the teleportation descriptor.</p>
</IonLabel></IonItem></IonList>};
export default {traits_tian_xia:_traits_tian_xia,traits_north_central_avistan:_traits_north_central_avistan,traits_casmaron:_traits_casmaron,traits_north_west_avistan:_traits_north_west_avistan,traits_north_east_avistan:_traits_north_east_avistan,traits_south_east_avistan:_traits_south_east_avistan,traits_south_west_avistan:_traits_south_west_avistan,traits_darklands:_traits_darklands,traits_extraplanar:_traits_extraplanar,traits_eye_of_abendego:_traits_eye_of_abendego,traits_generic:_traits_generic,traits_northwest_garund:_traits_northwest_garund,traits_northeast_garund:_traits_northeast_garund,traits_lung_wa:_traits_lung_wa,traits_mana_wastes:_traits_mana_wastes,traits_mwangi_expanse:_traits_mwangi_expanse,traits_river_kingdoms:_traits_river_kingdoms}